Set.Sql:
UPDATE GRP_COSTUMER SET GRP_ID= GRP_ID * -1 WHERE GRP_COS_ID IN (@IDS_SPLIT) AND SUP_ID=@G_SUP_ID AND GRP_ID=@GRP_ID AND NOT COS_ID IN ( SELECT DISTINCT COS_ID FROM GRP_FInANCE WHERE GRP_ID=@GRP_ID UNION SELECT DISTINCT USR_ID FROM VIS_TAB_MAIN WHERE VIS_TYPE<>'BASE'
) ; UPDATE GRP_FIN_TYPE SET GRP_ID=GRP_ID *-1 WHERE GRP_FIN_TYPE_FROM='GRP_COSTUMER' AND GRP_FIN_TYPE_REFID IN ( SELECT GRP_COS_ID FROM GRP_COSTUMER WHERE GRP_ID=@GRP_ID * -1 AND SUP_ID=@G_SUP_ID ) AND GRP_ID = @GRP_ID ;
exec pr_grp_bill @grp_id

Set.Bottom:
$(function(){
    //找不到title，手动加上
    $("#EWA_MG_@SYS_FRAME_UNID").parentsUntil(".grp-part")
        .parent().find(".grp-part-title").text("帐号统计");
    EWA.F.FOS["@SYS_FRAME_UNID"].ReloadAfter=function(){
        $("#EWA_MG_@SYS_FRAME_UNID .EWA_GRID_H:eq(0)").css({"white-space":"nowrap"});

        var u=this.getUrlClass();
        var curYear=u.GetParameter("CUR_YEAR");

        var ht=[];
        //ht.push("<select>");
        var i="@EWA.DATE.YEAR"*1;
        for(;i>=2013;i--){
            ht.push("<option value='"+i+"' "
            + (curYear==i?"selected":"")
            +">"+i+"</option>");
        }
        //ht.push("</select>");
        //$("#EWA_MG_@SYS_FRAME_UNID .EWA_GRID_H:eq(0)").html(ht.join(""));
        $("#gd_mnu_sel_year_@sys_frame_unid").html(ht.join(""));
        $("#gd_mnu_sel_year_@sys_frame_unid").on("change",function(){
            var u=EWA.F.FOS["@SYS_FRAME_UNID"].getUrlClass();
            u.AddParameter("CUR_YEAR",$(this).val());
            EWA.F.FOS["@SYS_FRAME_UNID"].Url=u.GetUrl();
            EWA.F.FOS["@SYS_FRAME_UNID"].Reload();
        });


        //隐藏空白列
        $("#gd_mnu_but_toggle_@sys_frame_unid").on("click",function(){
            var hid=$(this).attr("data-hide");
            if(hid=="1"){
                $(this).attr("data-hide","0");
                $(this).html("隐藏空白列");
                $("#EWA_MG_@SYS_FRAME_UNID td").show();
            }else{
                $(this).attr("data-hide","1");
                $(this).html("显示空白列");

                var tr_len=$("#EWA_MG_@SYS_FRAME_UNID tr").length;
                var td_len=$("#EWA_MG_@SYS_FRAME_UNID td.EWA_GRID_H").length;
                for(var i=1;i<td_len;i++){
                    var v="";
                    for(var j=1;j<tr_len;j++){
                        v+=$("#EWA_MG_@SYS_FRAME_UNID tr").eq(j).children().eq(i).attr("val").trim();
                        if(v){
                            break;
                        }
                    }
                    if(!v){
                       for(var j=0;j<tr_len;j++){
                            $("#EWA_MG_@SYS_FRAME_UNID tr").eq(j).children().eq(i).hide();
                        } 
                    }
                }
            }
        }).click();
    }
    EWA.F.FOS["@SYS_FRAME_UNID"].ReloadAfter();
})

$(function() {
    EWA.F.FOS["@SYS_FRAME_UNID"].ReloadAfter = function() {
        //下载链接绑定事件
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-lkDownload a").on("click", function() {
            var id = $(this).attr("data-currency-id");
            var u = EWA.CP + '/back_admin/scm/crr_up_file_download.jsp?CURRENCY_ID=' + id;
            window.open(u);
        });
        //文件名绑定查看事件
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-FILE_NAME a").on("click", function() {
            var id = $(this).attr("data-currency-id");
            var md5 = $(this).attr("data-pic-md5");
            var u = EWA.CP + '/robert/v.jsp?tb=CURRENCY_FILE&CURRENCY_ID=' + id + "&md5=" + md5;
            if (top == window) {
                window.open(u);
            } else {
                top.frames[0].AddTab(u, '查看询价单（' + id + ')');
            }
        });
        //格式化文件大小
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-CURRENCY_OB2 span").each(function(){
            var t=$(this).text();
            if(t && t!="0"){
                t=t*1;
                if(t<1024){
                    t=t+"B";
                }else if(t<1024*1024){
                    t=(t/1024).toFixed(2)+"XK";
                }else{
                    t=(t/1024/1024).toFixed(2)+"XM";
                }
                t=t.replace(".00X","");
                t=t.replace("0X","");
                t=t.replace("X","");
                $(this).html(t);
            }
        });
    }
    EWA.F.FOS["@SYS_FRAME_UNID"].ReloadAfter();
});

