Set.Bottom:
$(function() {
    var ewa = EWA.F.FOS["@sys_frame_unid"];
    ewa.valid_targets = ["PAX", "CITYS", "DAYS"];
    ewa.ReloadAfter = function() {
        var tb = $('#EWA_LF_@SYS_FRAME_UNID')
            //添加下一行事件元素添加样式
        for (var i = 0; i < this.valid_targets.length; i++) {
            $("#EWA_LF_" + this.Id + " .ewa-lf-data-row .ewa-col-" + this.valid_targets[i]).addClass("customer-add-row-td");
        }
        //已报名Title，改为Students + Leaders
        tb.find(".ewa-col-PAX #PAX").each(function() {
            var title = $(this).attr("data-pax-title");
            $(this).attr("title", title).parent().attr("title", title);
        });


        //绑定按钮事件
        //打开团控制面板
        tb.find("input[id=butPanel]").on("click", function() {
            var grp_id = $(this).attr("data-grp-id");

            var grp_hy_code = $(this).attr("data-grp-hy-code");
            var enq_id = $(this).attr("data-enq-id");
            var nums1 = $(this).attr("data-ppnum");
            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            var p = 'grp_id=' + grp_id + '&enq_id=' +
                enq_id + '&nums=' + nums1 +
                '&grp_hy_code=' + grp_hy_code + '&xml=grp_detail.xml';
            if (u1.GetParameter("T")) {
                p += "&T=" + u1.GetParameter("T");
            } else {
                p += "&T=12";
            }
            //var u = EWA.CP + '/robert/r_grp2.jsp?' + p;
            //var u= EWA.CP +"/robert/grp-2019/grp.jsp?"+p;
            var u = EWA.CP + "/2019/grp/grp.jsp?" + p;
            if (top.AddTab && top != window) {
                top.AddTab(u);
            } else {
                window.open(u);
            }
        });

        //显示团报名二维码
        tb.find(".ewa-col-qrcode a").on("click", function() {
            var objParent = $(this).parent();
            var grp_id = objParent.attr("data-grp-id");
            grpIds.push(grp_id);
            var grp_hy_code = objParent.attr("data-grp-hy-code");
            var grp_name = objParent.attr("data-grp-name");
            var grp_run_model = objParent.attr("data-grp-run-model");

            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            u1.RemoveEwa();
            u1.AddParameter("GRP_ID", grp_id);
            u1.AddParameter("GRP_HY_CODE", grp_hy_code);
            u1.AddParameter("GRP_NAME", grp_name);
            var u = EWA.CP + "/app-2017/crm/enroll.jsp?FROM=customer&" + u1.GetParas();
            if (grp_run_model == 'GRP_RUN_SINGLE') {
                u += "&SID=3";
            }
            var dia = window.top.$DialogInstall(u);
        });

        var grpIds = [];
        var mapGrp = {};
        tb.find('.ewa-lf-data-row').each(function() {
            var grp_id = $(this).attr('ewa_key');
            grpIds.push(grp_id);
            mapGrp[grp_id] = $(this);
        });

        var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "LoadData");
        u1.AddParameter("ewa_ajax", "json_all");
        var data = {
            "ids_split": grpIds.join(",")
        };
        var u = u1.GetUrl();
        $JP(u, data, function(rst) {

            var airData = rst[0];
            var map = {};
            for (var n in airData) {
                var d = airData[n]; //数据行
                var grpid = d.GRP_ID;

                if (!map[grpid]) {
                    map[grpid] = [];
                }
                map[grpid].push("<div title=\"" + d.SUP_NAME + "\">" + d.SUP_NAME + "</div>");

            }
            for (var gid in map) {
                var arr = map[gid]; //数据行
                var tr = mapGrp[gid];
                if (!tr) {
                    console.log('找不到grp_id=' + gid + "的tr");
                    continue;
                }
                tr.find('[name=CP_AIR_TICKET]').html(arr.join(""));
            }
        });

    }
    ewa.ReloadAfter();

    ewa.ext_GrpGroupByDept=function(){
        let u1=ewa.getUrlClass();
        u1.RemoveEwa();
        u1.AddParameter("XMLNAME","/business/group/grp_group_dept_acl.xml");
        u1.AddParameter("ITEMNAME","GRP_GROUP_MAIN.LF.M");
        top.AddTab(u1.GetUrl());
    }

    ewa.AddPreRow(
        function(frameUnid, tr, key, newTr, evt) {
            var target = evt.target;
            var cur_target_id = "";
            var target_obj;
            for (var i = 0; i < this.valid_targets.length; i++) {
                var id = this.valid_targets[i];
                if ($(target).hasClass("ewa-col-" + id)) {
                    target_obj = target;
                    cur_target_id = id;
                } else if (target.id == id) {
                    target_obj = $(target).parent()[0];
                    cur_target_id = id;
                }
                if (cur_target_id) {
                    break;
                }
            }
            var enq_id = $(tr).find("#GRP_HY_CODE").attr("data-enq-id");
            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            u1.AddParameter("EWA_AJAX", "INSTALL");
            u1.AddParameter("GRP_ID", key);
            if (cur_target_id == "PAX") {
                u1.AddParameter("XMLNAME", "/business/group/signup.xml");
                u1.AddParameter("ITEMNAME", "GRP_COSTUMER.ListFrame.Modify");
                u1.AddParameter("T", "12");
            } else if (cur_target_id == "CITYS" || cur_target_id == "DAYS") {
                u1.AddParameter("XMLNAME", "|business|group|signup.xml");
                u1.AddParameter("ITEMNAME", "ENQ_JNY.LF.V");
                u1.AddParameter("ENQ_ID", enq_id);
            } else {
                return;
            }

            var cnt_td = newTr.cells[0];
            $(cnt_td).addClass('add-pre-row');

            $(target_obj).addClass("customer-add-row-cur-td");
            var ajax_url = u1.GetUrl();
            $Install(ajax_url, cnt_td.id, function() {
                // console.log('install ok');
            });
        }
    );

    ewa.AddPreRowCheck = function(tr, key, evt) {
        $("#EWA_LF_" + this.Id + " .customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
        var target = evt.target;
        for (var i = 0; i < this.valid_targets.length; i++) {
            var id = this.valid_targets[i];
            if ($(target).hasClass("ewa-col-" + id) || target.id == id) {
                return true;
            }
        }

        if (this.prevTr) {
            $(this.prevTr).remove();
            this.prevTr = null;
        }

        return false;
    };

    ewa.AddPreRowCloseEvent = function(frameUnid, tr, key, newTr, evt) {
        $(evt.target).parentsUntil("tr").parent().find(".customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
    }

    ewa.ext_gyap_cat = function(grpId,t){
        var sync_url="@ewa.cp/2019/api/sync-b2b.jsp?pk_value="+grpId;
        var itemname;
        if(t=="school"){
            itemname="camp_lesson_school_cat.T.ChangeNode";
        }else{
            itemname="camp_lesson_biz_cat.T.ChangeNode"
        }
        $J(sync_url,function(rst){
            if(!rst.RST){
                $Tip(rst.ERR);
                return;
            }
            var data=rst.DATA;
            var ids=data.DS_B2B_ID;


            var ref="user/ewa.jsp?XMLNAME=/2014_b2b/live/lesson-category.xml&ITEMNAME="+itemname
                +"&EWA_TREE_SKIP_GET_STATUS=1&ref_table=grp_card&ids="+ids;
            ref+="&EWA_P_BEHAVIOR=RELOAD_PARENT,CLOSE_SELF&EWA_PARENT_FRAME=@SYS_FRAME_UNID";
            var u="@ewa.cp/robert/sync_b2b/remote_login.jsp?ref="
                +encodeURIComponent(ref);
            EWA.UI.Dialog.OpenWindow(u,"",700,450,false);

            window.setTimeout(function() {
                //同步团设置为默认的课程(教案号：GRP_CARD)
                var ref2="user/ewa.jsp?XMLNAME=/2014_b2b/live/grp-card.xml&ITEMNAME=grp_main.LF.M"
                    +"&ewa_action=setLessonId&ewa_ajax=json&ids="+ids;
                var u2="@ewa.cp/robert/sync_b2b/remote_login.jsp?ref="+encodeURIComponent(ref2);
                $J3(u2,function(){});
            }, 1000);
        });
    }


    ewa.ext_CreateEncollQrcode = function(grpUnid) {
        let u = "/pf/back_admin/common/create-short-url.jsp?create=1&only_number=1";
        let domain = location.host.indexOf('gdx') >= 0 ? "gdx8" : "www.gyap.org";
        let target_url = "https://" + domain + "/pf/customer/study-tour/enrollframe.jsp?grp_unid=" + grpUnid;
        var data = {
            u: target_url
        };
        $JP(u, data, function(rst) {
            let surl = ""
            if (!rst.RST) {
                alert(rst.ERR);
            } else {
                if (domain == "gdx8") { // 本地测试
                    showQrCode1(rst.su.replace('gyap.org', domain));
                } else {
                    showQrCode1(rst.su);
                }
            }
        });
    };

    function showQrCode1(shortUrl) {
        let tr = EWA.F.FOS['@SYS_FRAME_UNID'].SelectCheckedRows()[0];
        let name = $(tr).find(".ewa-col-GRP_NAME").text().trim() + "_" + $(tr).find(".ewa-col-GRP_CODE").text().trim();
        let surl = "<div style='margin:0 12px;font-size:16px;text-align:center;'>" +
            "网址: <a href='" + shortUrl + "' target='_blank'>" + shortUrl + "</a></div>";

        var u = new EWA_UrlClass("/pf/back_admin/common/qrcode.jsp");
        u.AddParameter("msg", shortUrl);
        u.AddParameter("width", 300);
        var url = u.GetUrl();

        let exLink = '<a class="fa fa-external-link" href="' + shortUrl + '"' +
            'target="_blank" style="float: right;margin: 0 8px;font-size: 14px;"></a>';

        let ta = "<textarea style='display:none'>" + shortUrl + "</textarea>";
        let cp = "<a href='javascript:void(0)' " +
            " title='复制网址'" +
            " class='fa fa-copy' style='font-size:14px;text-decoration:none;margin-left:12px;cursor:pointer'" +
            " onclick=\"$(this).parent().find('textarea').show()[0].select();document.execCommand('copy');$(this).parent().find('textarea').hide();" +
            "$Tip('已复制')\"" +
            "></a>";

        top.$DialogHtml("<div style='margin:15px auto;text-align:center;font-size:20px;'>" +
            "<img src='" + url + "' style='max-width:300px;border:1px solid #ccc;padding:2px;' />" +
            "<br><br><a target='_blank' href='" + url + "' download='" + name + ".jpg'>下载报名二维码</a><br><br>" +
            shortUrl + cp + ta + "</div>" + exLink, '', 400, 400, true);
    }
});


