$(function(){
    EWA.F.FOS["@SYS_FRAME_UNID"].ReloadAfter=function(){
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-BUDGET_COST span").append("/人");
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-BUDGET_PROFIT span").append("/人");

        //修改select查询类型为
        function searchSelectFix2Lk(id){
            $("#_G_@SYS_FRAME_UNID .ewa-ref-"+id+" select").attr("t","lk");
        }
        //使用查询select中的名称替换列表标签
        function showTagName(id){
            var opts={};
            $("#_G_@SYS_FRAME_UNID .ewa-ref-"+id+" select option").each(function(){
               if(this.value){
                   opts[this.value]=this.text;
               }
            });
            $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-"+id+" span").each(function(){
                var tags=$(this).text().trim();
                if(!tags){
                    return true;
                }
                var names=[];
                var arr=tags.split(",");
                for(var i=0;i<arr.length;i++){
                    names.push(opts[arr[i]]);
                }
                $(this).html(names.join(','));
            });
        }

        searchSelectFix2Lk("ENQ_CAMP_ACCOMMODATION_TYPE");
        showTagName("ENQ_CAMP_ACCOMMODATION_TYPE");

        searchSelectFix2Lk("ENQ_CAMP_COURSE_TYPE");
        showTagName("ENQ_CAMP_COURSE_TYPE");

        //绑定打开询价面板按钮事件
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butEnq]").on("click",function(){
            var grp_id=$(this).attr("data-grp-id");
            var grp_hy_code=$(this).attr("data-grp-hy-code");
            var enq_id=$(this).attr("data-enq-id");
            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            var p = 'grp_id=' + grp_id + '&enq_id=' + enq_id 
                +'&grp_hy_code=' + grp_hy_code + '&xml=grp_detail.xml&';
            if(u1.GetParameter("T")){
                p+="&T="+u1.GetParameter("T");
            }
            var u = EWA.CP + '/robert/r_enq2.jsp?' + p;
            if (top.AddTab && top != window) {
                top.AddTab(u);
            } else {
                window.open(u);
            }
        });

        //绑定打开客户按钮事件
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butSupMain]").on("click",function(){
            var id=$(this).attr("data-com-id");
            var name=$(this).attr("data-sup-name");
            var u = "@EWA.CP/robert/r_crm2.jsp?T=10&crm_com_id=" + id;
            if (top != window && top.AddTab) {
                top.AddTab(u, name);
            } else {
                window.open(u);
            }
        })
    }
    EWA.F.FOS["@SYS_FRAME_UNID"].ReloadAfter();
});

