Set.Bottom:
$(function(){
    var ewa=EWA.F.FOS["@sys_frame_unid"];
    ewa.valid_targets=["PAX","CITYS","DAYS"];
    ewa.ReloadAfter=function(){
        //添加下一行事件元素添加样式
        for(var i=0;i<this.valid_targets.length;i++){
            $("#EWA_LF_"+this.Id+" .ewa-lf-data-row .ewa-col-"+this.valid_targets[i]).addClass("customer-add-row-td");
        }
        //已报名Title，改为Students + Leaders
        $("#EWA_LF_"+this.Id+" .ewa-col-PAX #PAX").each(function(){
            var title=$(this).attr("data-pax-title");
            $(this).attr("title",title).parent().attr("title",title);
        });

        //绑定按钮事件
        //打开团控制面板
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butPanel]").on("click",function(){
            var grp_id=$(this).attr("data-grp-id");
            var grp_hy_code=$(this).attr("data-grp-hy-code");
            var enq_id=$(this).attr("data-enq-id");
            var nums1=$(this).attr("data-ppnum");
            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            var p = 'grp_id=' + grp_id + '&enq_id=' +
                enq_id + '&t=@t&nums=' + nums1 +
                '&grp_hy_code=' + grp_hy_code + '&xml=grp_detail.xml';
            if(u1.GetParameter("T")){
                p+="&T="+u1.GetParameter("T");
            }else{
                p+="&T=12";
            }
            //var u = EWA.CP + '/robert/r_grp2.jsp?' + p;
            //var u= EWA.CP +"/robert/grp-2019/grp.jsp?"+p;
            var u= EWA.CP +"/2019/grp/grp.jsp?"+p;
            if (top.AddTab && top != window) {
                top.AddTab(u);
            } else {
                window.open(u);
            }
        });
        //显示团报名二维码
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-col-qrcode a").on("click",function(){
            var objParent=$(this).parent();
            var grp_id=objParent.attr("data-grp-id");
            var grp_hy_code=objParent.attr("data-grp-hy-code");
            var grp_name=objParent.attr("data-grp-name");
            var grp_run_model=objParent.attr("data-grp-run-model");

            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            u1.RemoveEwa();
            u1.AddParameter("GRP_ID",grp_id);
            u1.AddParameter("GRP_HY_CODE",grp_hy_code);
            u1.AddParameter("GRP_NAME",grp_name);
            var u = EWA.CP+"/app-2017/crm/enroll.jsp?FROM=customer&"+u1.GetParas();
        	if(grp_run_model == 'GRP_RUN_SINGLE'){
        		u+="&SID=3";
        	}
        	var dia=window.top.$DialogInstall(u);
        });
    }
    ewa.ReloadAfter();


    ewa.AddPreRow(
        function(frameUnid, tr, key, newTr, evt) {
            var target=evt.target;
            var cur_target_id="";
            var target_obj;
            for(var i=0;i<this.valid_targets.length;i++){
                var id=this.valid_targets[i];
                if($(target).hasClass("ewa-col-"+id)){
                    target_obj=target;
                    cur_target_id=id;
                }else if(target.id==id){
                    target_obj=$(target).parent()[0];
                    cur_target_id=id;
                }
                if(cur_target_id){
                    break;
                }
            }
            var enq_id=$(tr).find("#GRP_HY_CODE").attr("data-enq-id");   
            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            u1.AddParameter("EWA_AJAX", "INSTALL");
            u1.AddParameter("GRP_ID", key);
            if(cur_target_id=="PAX"){
                u1.AddParameter("XMLNAME","/business/group/signup.xml");
                u1.AddParameter("ITEMNAME","GRP_COSTUMER.ListFrame.Modify");
                u1.AddParameter("T","12");
            }else if(cur_target_id=="CITYS" || cur_target_id=="DAYS"){
                u1.AddParameter("XMLNAME","|business|group|signup.xml");
                u1.AddParameter("ITEMNAME","ENQ_JNY.LF.V");
                u1.AddParameter("ENQ_ID",enq_id);
            }else{
                return;
            }

            var cnt_td = newTr.cells[0]; 
            $(cnt_td).addClass('add-pre-row');

            $(target_obj).addClass("customer-add-row-cur-td");
            var ajax_url = u1.GetUrl();
            $Install(ajax_url, cnt_td.id, function() {
                // console.log('install ok');
            });
        }
    );

    ewa.AddPreRowCheck = function(tr, key, evt) {
        $("#EWA_LF_"+this.Id+" .customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
        var target=evt.target;
        for(var i=0;i<this.valid_targets.length;i++){
            var id=this.valid_targets[i];
            if($(target).hasClass("ewa-col-"+id) || target.id==id){
                return true;
            }
        }

        if(this.prevTr){
            $(this.prevTr).remove();
            this.prevTr=null;
        }

        return false;
    };

    ewa.AddPreRowCloseEvent=function(frameUnid, tr, key, newTr, evt){
        $(evt.target).parentsUntil("tr").parent().find(".customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
    }
});

