            var grp_name = objParent.attr("data-grp-name");
            var grp_run_model = objParent.attr("data-grp-run-model");

            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            u1.RemoveEwa();
            u1.AddParameter("GRP_ID", grp_id);
            u1.AddParameter("GRP_HY_CODE", grp_hy_code);
            u1.AddParameter("GRP_NAME", grp_name);
            var u = EWA.CP + "/app-2017/crm/enroll.jsp?FROM=customer&" + u1.GetParas();
            if (grp_run_model == 'GRP_RUN_SINGLE') {
                u += "&SID=" + $(this).closest("tr").attr("data-sup-down-id");
            }
            var dia = window.top.$DialogInstall(u);
        });
        */


        var grpIds = [];
        var mapGrp = {};
        tb.find('.ewa-lf-data-row').each(function() {
            var grp_id = $(this).attr('ewa_key');
            grpIds.push(grp_id);
            mapGrp[grp_id] = $(this);
        });

        var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "LoadData");
        u1.AddParameter("ewa_ajax", "json_all");
        var data = {
            "ids_split": grpIds.join(",")
        };
        var u = u1.GetUrl();
        $JP(u, data, function(rst) {

            var airData = rst[0];
            var map = {};
            for (var n in airData) {
                var d = airData[n]; 
                var grpid = d.GRP_ID;
                if (!map[grpid]) {
                    map[grpid] = [];
                }
                map[grpid].push("<div title=\"" + d.SUP_NAME + "\">" + d.SUP_NAME + "</div>");
            }
            for (var gid in map) {
                var arr = map[gid];  
                var tr = mapGrp[gid];
                if (!tr) {
                    console.log('找不到grp_id=' + gid + "的tr");
                    continue;
                }
                tr.find('[name=CP_AIR_TICKET]').html(arr.join(""));
            }
        });

        getObj("tr.ewa-lf-data-row").each(function() {
            let formId = $(this).attr("data-grp-form-id");
            if (formId && formId != "-1" && formId != "0") {
                let grpSta = $(this).attr("data-grp-sta");
                if (grpSta == "SCM_GRP_STA_NEW") {
                    $(this).find("#SUP_NAME").css({
                        "color": "#f60"
                    }).attr("title", "客户提交询价需求");
                }
            }
        })
    }
