    ewa.ext_GrpGroupByDept = function() {
        let u1 = ewa.getUrlClass();
        u1.RemoveEwa();
        u1.AddParameter("XMLNAME", "/business/grp/grp_group_dept_acl.xml");
        u1.AddParameter("ITEMNAME", "GRP_GROUP_MAIN.LF.M");
        top.AddTab(u1.GetUrl());
    }

    ewa.AddPreRow(        function(frameUnid, tr, key, newTr, evt) {
            var target = evt.target;
            var cur_target_id = "";
            var target_obj;
            for (var i = 0; i < this.valid_targets.length; i++) {
                var id = this.valid_targets[i];
                if ($(target).hasClass("ewa-col-" + id)) {
                    target_obj = target;
                    cur_target_id = id;
                } else if (target.id == id) {
                    target_obj = $(target).parent()[0];
                    cur_target_id = id;
                }
                if (cur_target_id) {
                    break;
                }
            }
            var enq_id = $(tr).find("#GRP_HY_CODE").attr("data-enq-id");
            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            u1.AddParameter("EWA_AJAX", "INSTALL");
            u1.AddParameter("GRP_ID", key);
            if (cur_target_id == "PAX") {
                u1.AddParameter("XMLNAME", "/business/group/signup.xml");
                u1.AddParameter("ITEMNAME", "GRP_COSTUMER.ListFrame.Modify");
                if("@VIEW_ACL"){
                    u1.AddParameter("T", "12");
                }
            // } else if (cur_target_id == "CITYS" || cur_target_id == "DAYS") {
            //     //u1.AddParameter("XMLNAME", "business/group/signup.xml");
            //     //u1.AddParameter("ITEMNAME", "ENQ_JNY.LF.V");
            //     u1.AddParameter("XMLNAME", "/business/gyap-project/design.xml")
            //     u1.AddParameter("ITEMNAME", "ENQ_JNY.Lf.design");
            //     u1.AddParameter("ENQ_ID", enq_id);
            } else {
                return;
            }

            var cnt_td = newTr.cells[0];
            $(cnt_td).addClass('add-pre-row');

            $(target_obj).addClass("customer-add-row-cur-td");
            var ajax_url = u1.GetUrl();
            $Install(ajax_url, cnt_td.id, function() {
            });
        }
    );

    ewa.AddPreRowCheck = function(tr, key, evt) {
        if('@ref_grp_id'){
            return false;
        }
        $("#EWA_LF_" + this.Id + " .customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
        var target = evt.target;
        for (var i = 0; i < this.valid_targets.length; i++) {
            var id = this.valid_targets[i];
            if ($(target).hasClass("ewa-col-" + id) || target.id == id) {
                return true;
            }
        }

        if (this.prevTr) {
            $(this.prevTr).remove();
            this.prevTr = null;
        }

        return false;
    };

    ewa.AddPreRowCloseEvent = function(frameUnid, tr, key, newTr, evt) {
        $(evt.target).parentsUntil("tr").parent().find(".customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
    }

    ewa.ext_gyap_cat = function(grpId, t) {
        var sync_url = "@ewa.cp/2019/api/sync-b2b.jsp?pk_value=" + grpId;
        var itemname;
        if (t == "school") {
            itemname = "camp_lesson_school_cat.T.ChangeNode";
        } else {
            itemname = "camp_lesson_biz_cat.T.ChangeNode"
        }
        $J(sync_url, function(rst) {
            if (!rst.RST) {
                $Tip(rst.ERR);
                return;
            }
            var data = rst.DATA;
            var ids = data.DS_B2B_ID;


            var ref = "user/ewa.jsp?XMLNAME=/2014_b2b/live/lesson-category.xml&ITEMNAME=" + itemname +
                "&EWA_TREE_SKIP_GET_STATUS=1&ref_table=grp_card&ids=" + ids;
            ref += "&EWA_P_BEHAVIOR=RELOAD_PARENT,CLOSE_SELF&EWA_PARENT_FRAME=@SYS_FRAME_UNID";
            var u = "@ewa.cp/robert/sync_b2b/remote_login.jsp?ref=" +
                encodeURIComponent(ref);
            EWA.UI.Dialog.OpenWindow(u, "", 700, 450, false);

            window.setTimeout(function() {
                // 同步团设置为默认的课程(教案号：GRP_CARD)
                var ref2 = "user/ewa.jsp?XMLNAME=/2014_b2b/live/grp-card.xml&ITEMNAME=grp_main.LF.M" +
                    "&ewa_action=setLessonId&ewa_ajax=json&ids=" + ids;
                var u2 = "@ewa.cp/robert/sync_b2b/remote_login.jsp?ref=" + encodeURIComponent(ref2);
                $J3(u2, function() {});
            }, 1000);
        });
    }


    ewa.ext_open_enq_jny_pic_lib = function() {
        var u = "@EWA.CP/ewa.jsp";
        u += "?XMLNAME=/business/gyap-project/design.xml";
        u += "&ITEMNAME=PIC_MAIN.LF.M_PIC_LIB";
        u += "&PIC_LIB=ENQ_JNY_PIC_LIB";
        var w = $(window).width() - 28;
