        if (top && top.AddTab) {
            window.top.AddTab(u, "图片库");
        } else {
            window.open(u);
        }
    }

    ewa.ext_poster_lib = function() {
        let u = "@EWA.CP/poster-design/pd-list.jsp?REF_TABLE=STUDY_TOUR&PD_TAG=STUDY_TOUR";
        if (top && top.AddTab) {
            window.top.AddTab(u, "海报模板库");
