        }
    }

    ewa.ext_poster = function(connId,grpId){
        let paras="REF_TABLE=GRP_MAIN.ENROLL&PD_TAG=STUDY_TOUR&ewa_in_dialog=1&EWA_HEIGHT=400";
        paras+="&REF_ID"+grpId;
        if(connId){
            paras+="&EWA_MTYPE=M&CONN_ID="+connId;
