        }
        EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid","/business/poster-design/pd-list.xml", "PD_CONN.F.NM"
            ,false, paras);
    }

    function init() {
        let pastGrp = "<b class='fa fa-calendar'>过期询价</b>";
        $("div.ewa-lf-func-recycle[onclick='EWA.F.FOS[\"@sys_frame_unid\"].ShowRecycle1(this)']").html(pastGrp);
