$(function() {
    var ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    ewa.ReloadAfter = function() {
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-COST span").append("万");
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-PAY_REAL span").append("万");
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-IN_PLAN span").append("万");
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-IN_REAL span").append("万");
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-PB span").append("万");

        //添加下一行事件元素添加样式
        for (var i = 0; i < this.valid_targets.length; i++) {
            $("#EWA_LF_" + this.Id + " .ewa-col-" + this.valid_targets[i]).addClass("customer-add-row-td");
        }
        //添加查看链接文字内容
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-col-linkView a").html(ewa.Resources.lkView.GetInfo());
    };
    ewa.valid_targets = ["ENQ_GRPS", "BOOK_GRPS", "IN_GRPS"];
    ewa.AddPreRow(function(frameUnid, tr, key, newTr, evt) {
        var target = evt.target;
        var cur_target_id = "";
        var target_obj;
        for (var i = 0; i < this.valid_targets.length; i++) {
            var id = this.valid_targets[i];
            if ($(target).hasClass("ewa-col-" + id)) {
                target_obj = target;
                cur_target_id = id;
            } else if (target.id == id) {
                target_obj = $(target).parent()[0];
                cur_target_id = id;
            }
            if (cur_target_id) {
                break;
            }
        }
        var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        //u1.AddParameter("EWA_AJAX", "INSTALL");
        u1.AddParameter("BY_CAMP_ID", key);
        if (cur_target_id == "ENQ_GRPS") {
            u1.AddParameter("XMLNAME", "@xmlname");
            u1.AddParameter("ITEMNAME", "index-sub-ENQ_MAIN.LF.M");
        } else if (cur_target_id == "BOOK_GRPS" || cur_target_id == "IN_GRPS") {
            u1.AddParameter("XMLNAME", "@xmlname");
            u1.AddParameter("ITEMNAME", "index-sub-GRP_MAIN.LF.M");
            if (cur_target_id == "BOOK_GRPS") {
                u1.AddParameter("GRP_STA", "SCM_GRP_STA_UNENQ");
            }
        } else {
            return;
        }

        var cnt_td = newTr.cells[0];
        $(cnt_td).addClass('add-pre-row');

        $(target_obj).addClass("customer-add-row-cur-td");
        var root_ajax = u1.GetUrl();
        $Install(root_ajax, cnt_td.id, function() {});

    });

    ewa.AddPreRowCheck = function(tr, key, evt) {
        $("#EWA_LF_" + this.Id + " .customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
        var target = evt.target;
        for (var i = 0; i < this.valid_targets.length; i++) {
            var id = this.valid_targets[i];
            if ($(target).hasClass("ewa-col-" + id) || target.id == id) {
                return true;
            }
        }

        if (this.prevTr) {
            $(this.prevTr).remove();
            this.prevTr = null;
        }

        return false;
    };

    ewa.AddPreRowCloseEvent = function(frameUnid, tr, key, newTr, evt) {
        $(evt.target).parentsUntil("tr").parent().find(".customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
    };

    ewa.ReloadAfter();
});
