$(function() {
    var ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    var u_root = ewa.getUrlClass();
    u_root.RemoveEwa();
    u_root.AddParameter("XMLNAME", "@XMLNAME");
    u_root.AddParameter("ITEMNAME", "@ITEMNAME");
    u_root.AddParameter("EWA_AJAX", "JSON");
    var u_ajax_url = u_root.GetUrl();

    function view_pax_list(t, grp_id) {
        var u = ewa.getUrlClass();
        u.RemoveEwa();
        u.AddParameter("XMLNAME", "@XMLNAME");
        u.AddParameter("ITEMNAME", "GRP_COSTUMER.LF.V_BY_IDS");
        u.AddParameter("EWA_AJAX", "JSON");
        u.AddParameter("EWA_ACTION", t);
        u.AddParameter("GRP_ID", grp_id);
        var url = u.GetUrl();
        $J1(url, function(datas) {
            if (!datas || datas.length == 0) {
                $Tip("没有客人");
                return;
            }
            var ids = [];
            for (var i = 0; i < datas.length; i++) {
                ids.push(datas[i].GRP_COS_ID);
            }
            var paras = "GRP_ID=" + grp_id + "&GRP_COS_IDS_SPLIT=" + ids.join(",");
            EWA.UI.Dialog.OpenFrame("@SYS_FRAME_UNID", "@XMLNAME", "GRP_COSTUMER.LF.V_BY_IDS", false, paras);
        });
    }
    //药物或过敏绑定查看人名单事件
    function bindAllergy() {
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-ALLERGIES a").each(function() {
            var v = $(this).text();
            if (!v || v == "0") {
                $(this).hide();
            } else {
                $(this).on("click", function() {
                    var grp_id = $(this).parentsUntil("tr").parent().attr("ewa_key");
                    view_pax_list("getAllergyIds", grp_id);
                });
            }
        });
    }
    //查看导出保险名单，设置保险完成
    function bindInsure() {
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-butInsure input[type='button']").on("click", function() {
            var u = ewa.getUrlClass();
            u.RemoveEwa();
            u.AddParameter("XMLNAME", "/business/group/insure.xml");
            u.AddParameter("ITEMNAME", "GRP_COSTUMER.ListFrame.Modify")
            u.AddParameter("GRP_ID", $(this).parentsUntil("tr").parent().attr("ewa_key"));
            var url = u.GetUrl();
            var dia = EWA.UI.Dialog.OpenWindow(url, "index_2019_insure_list", 950, 500, false);
        });
    }

    //绑定住宿分配事件
    function bindAccomodation(){
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row")
            .find(".ewa-col-butAccommodation input[type='button'],.ewa-col-GRP_HOME_STATE a").on("click",function(){
                var title="@sys_ewa_lang"=="enus"?"Accommodation":"住宿分配";
                var tr=$(this).parentsUntil("tr").parent().first();
                var grp_id=tr.attr("ewa_key");
                var grp_no=tr.find("td.ewa-col-GRP_HY_CODE").text().trim();
                title+="("+grp_no+")";

                var u="ewa.jsp?XMLNAME=/business/group/signup.xml&ITEMNAME=V_GRP_COS_INFO.LF.V&EWA_FRAMESET_NO=1&GRP_ID="+grp_id;
                window.top.AddTab(u,title);
        });
    }
    //异步加载住宿分配信息
    function asyncAccommodation() {
        var ids = [];
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row").each(function() {
            ids.push($(this).attr("ewa_key"));
        });
        var u = new EWA_UrlClass(u_ajax_url);
        u.AddParameter("EWA_ACTION", "getAccommodation");
        u.AddParameter("GRP_IDS_SPLIT", ids.join(","));
        $J1(u.GetUrl(), function(data) {
            var tags = {};
            tags["HOME"] = "@sys_ewa_lang" == "enus" ? "F " : "家";
            tags["HOTEL"] = "@sys_ewa_lang" == "enus" ? "H " : "酒";
            tags["DORM"] = "@sys_ewa_lang" == "enus" ? "D " : "宿";
            var grp_data = $J2MAP1(data, "GRP_ID");
            for (var grp_id in grp_data) {
                var ht = [];
                for (var idx in grp_data[grp_id]) {
                    var d = grp_data[grp_id][idx];
                    ht.push(tags[d.TAG] + d.COS_NUM);
                }
                var obj=$("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row[ewa_key=" + grp_id + "] .ewa-col-GRP_HOME_STATE a");
                if(obj.attr("data-grp-home-state")=="GRP_HOME_STATE_NONE"){//未安排状态的显示,否则title
                    obj.append("/<span style='color:green'>"+ht.join("/")+"</span>")
                }else{
                    obj.attr("title",ht.join("/n"));
                }
            }
        });
    }

    //异步加载分班
    function asyncClassGrouping() {
        var ids = [];
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row").each(function() {
            ids.push($(this).attr("ewa_key"));
        });
        var u = new EWA_UrlClass(u_ajax_url);
        u.AddParameter("EWA_ACTION", "getClassGrouping");
        u.AddParameter("GRP_IDS_SPLIT", ids.join(","));
        $J1(u.GetUrl(), function(data) {
            for (var i = 0; i < data.length; i++) {
                $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row[ewa_key=" + data[i].GRP_ID + "] .ewa-col-CLASS_GROUPING span").html(data[i].CLASS_NUM);
            }
        });
    }

    ewa.ReloadAfter = function() {
        //药物或过敏
        bindAllergy();
        //保险
        bindInsure();
        //住宿安排打开事件
        bindAccomodation();
        //住宿
        asyncAccommodation();
        //分班
        asyncClassGrouping();
    }
    ewa.ReloadAfter();
});

