function viewLastYear() {
    var xmlName = "@xmlname";
    var itemName = "@itemname";
    var paras = "pop=1&EWA_PAGESIZE=5";
    var sdate = $(".ewa-lf-search-item.ewa-ref-GRP_SDATE input[name=GRP_SDATE]").val();
    var sdate1 = $(".ewa-lf-search-item.ewa-ref-GRP_SDATE input[name=GRP_SDATE1]").val();
    if (!sdate || !sdate1) {
        $Tip("请选择开团的起止日期");
        return;
    }
    var obj_sdate = new EWA_DateClass(sdate);
    if (obj_sdate.GetMonth() == 2 && obj_sdate.GetDay() == 29) {
        obj_sdate.AddDays(-366);
    } else {
        obj_sdate.AddDays(-365);
    }
    var obj_sdate1 = new EWA_DateClass(sdate1);
    if (obj_sdate1.GetMonth() == 2 && obj_sdate1.GetDay() == 29) {
        obj_sdate1.AddDays(-366);
    } else {
        obj_sdate1.AddDays(-365);
    }
    var ft_sdate = obj_sdate.FormatDate();
    var ft_sdate1 = obj_sdate1.FormatDate();
    var last_date = "GRP_SDATE[gte]" + ft_sdate + ",GRP_SDATE[lte]" + ft_sdate1;
    var cur_date = "GRP_SDATE[gte]" + sdate + ",GRP_SDATE[lte]" + sdate1;
    var searchPara = searchGetExpPara($X("@SYS_FRAME_UNID" + "_SEARCH_ITEM"));
    searchPara = searchPara.replace(cur_date, last_date);
    paras += "&EWA_SEARCH=" + encodeURIComponent(searchPara);
    EWA.UI.Dialog.OpenFrame("@SYS_FRAME_UNID", xmlName, itemName, false, paras);
}

function searchGetExpPara(tb) {
    var s2 = [];
    $(tb).find('.ewa-lf-search-item').each(function() {
        var inputs = $(this).find('input');
        if (inputs.length == 0) {
            inputs = $(this).find('select');
            if (inputs.length == 0) {
                return;
            }
        }
        var input0 = inputs[0];
        var search_type = $(input0).attr('t');
        if (inputs.length == 1) {
            var v = input0.value;
            if (input0.value.trim() == '') {
                return;
            }
            if (search_type == 'text') {
                var tag1 = $(input0.parentNode.parentNode).find('a').attr('tag');
                if (tag1) {
                    search_type = tag1;
                }
            }
            s2.push(input0.name + "[" + search_type + "]" + v);
            return;
        }
        if ((search_type == 'date' || search_type == 'number') && inputs.length == 2) {
            var v = input0.value;
            var v1 = inputs[1].value;
            if (v1 == '' && v == '') {
                return;
            }
            s2.push(input0.name + "[gte]" + v);
            if (v1) {
                s2.push(input0.name + "[lte]" + v1);
            }
            return;
        }
        if (search_type == 'fix' && input0.tagName == 'INPUT') {
            var vs = [];
            $(this).find('input').each(function() {
                if (this.checked) {
                    vs.push(this.value);
                }
            });
            if (vs.length == 0) { // 没有数据
                return;
            }
            s2.push(input0.name + "[or]" + vs.join(";"));
        }
    });
    return s2.join(',');
}

