        var ajax_url = u1.GetUrl();
        $Install(ajax_url, cnt_td.id, function() {});
    });
    EWA.F.FOS["@SYS_FRAME_UNID"].openGrp = function(grpId) {
        let u = '@ewa.cp/business/group/grp-index.jsp?grp_id='+grpId;
        if(top.AddTab){
            top.AddTab(u);
        } else {
            window.open(u);
        }
    };
    EWA.F.FOS["@SYS_FRAME_UNID"].ReloadAfter = function() {
        if ($("#EWA_LF_@SYS_FRAME_UNID>tbody>tr").length > 1) {
            //添加全部数据的汇总数，插入在最上边，黑色粗体，格式化为xx.xx万
            var sumTds = $($("#EWA_LF_@SYS_FRAME_UNID>tbody>tr").last().html());
            sumTds.find("nobr").html("").css({
                "font-weight": "bold",
                "color": "#333"
            });

            var nb = sumTds.find("nobr").eq(0).parent().html();

            var sumTr = $("<tr></tr>");
            for (var i = 0; i < sumTds.length; i++) {
                var td = sumTds.eq(i);
                td.attr("id", td.attr("id").replace("ADD_ROW_", "INS_ROW_"));
                sumTr.append(td);
            }
            $("#EWA_LF_@SYS_FRAME_UNID>tbody>tr:eq(0)").after(sumTr);

            $("#EWA_LF_@SYS_FRAME_UNID #INS_ROW_IN_PER").html(nb);
            $("#EWA_LF_@SYS_FRAME_UNID #INS_ROW_WZF_PER").html(nb);
            $("#EWA_LF_@SYS_FRAME_UNID #INS_ROW_GRP_HY_CODE").html(nb);

            var u = this.getUrlClass();
            u.AddParameter("EWA_AJAX", "JSON");
            u.AddParameter("EWA_ACTION", "getSummary");
            var searchExp = this.SearchGetExp($("#" + "@SYS_FRAME_UNID" + "_SEARCH_ITEM")[0]);
            u.AddParameter("EWA_LF_SEARCH", searchExp);
            $J1(u.GetUrl(), function(data) {
                if (data && data.length > 0) {
                    for (var n in data[0]) {
                        var v = data[0][n] * 1;
                        var v2;
                        var vw;
                        if (n == "PPNUM" || n == "PAX" || n == "GRP_HY_CODE") {
                            v2 = vw = v;
                        } else if (n == "IN_PER" || n == "WZF_PER") {
                            v2 = (v * 100).toFixed(2) + "%";
                            vw = v2;
                        } else {
                            v2 = v.fm(2);
                            vw = (v / 10000).fm(2) + "万";
                        }
                        $("#EWA_LF_@SYS_FRAME_UNID #INS_ROW_" + n + " nobr").html(vw).attr("title", v2);
                    }
                }
            });

            //当前页汇总数据添加title
            $("#EWA_LF_@SYS_FRAME_UNID td.ewa-lf-sub-td").each(function() {
                var id = $(this).attr("id").replace("ADD_ROW_", "");
                var txt = $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-header .ewa-col-" + id).text();
                $(this).attr("title", txt);
            });

        }
        //弹窗时resize一下
        if ("@pop" == "1") {
            resizePopWinSize();
        }
    }

    if ("@EWA_SEARCH" == "") {
        if ("@EWA_AJAX" == "" || "@EWA_AJAX".toUpperCase() == "INSTALL") {
            var dt = (new Date()).getFullYear() + '-01-01';
            var objDt = new EWA_DateClass(dt);
            var ftDt = objDt.FormatDate();
            $("#" + "@SYS_FRAME_UNID" + "_SEARCH_ITEM .ewa-ref-GRP_SDATE input:eq(0)").val(ftDt);
            return;
        } else {
            EWA.F.FOS["@SYS_FRAME_UNID"].ReloadAfter();
        }
    } else {
        if ("@pop" == "1") {
            //先强制刷新一次吧，不然不自动resize
            EWA.F.FOS["@SYS_FRAME_UNID"].ReloadAfter();
        }
    }
});

async function agent_master_login_qrcode_op(supDownId, crmComId, validTime) {
    let ewa = EWA.F.FOS["@sys_frame_unid"];
    let u1 = ewa.getUrlClass();
    u1.RemoveEwa();
    u1.AddParameter("xmlname", "@xmlname");
    u1.AddParameter("ITEMNAME", "index-CRM_COM.Lf.M");
    u1.AddParameter("EWA_AJAX", "json_all");
    u1.AddParameter("EWA_ACTION", "getMasterContact");
    //获取代理和联系人信息
    let rstAll = await new Promise((resolve) => {
        if (supDownId) {
            u1.AddParameter("SUP_DOWN_ID", supDownId);
        }
        if (crmComId) {
            u1.AddParameter("CRM_COM_ID", crmComId);
        }
        $J(u1.GetUrl(), function(rst) {
            return resolve(rst);
        });
    });

    let com = rstAll[0];
    if (com.length == 0 || !com[0]["SUP_DOWN_ID"]) {
        $Tip("还未签约");
        return;
    }
    supDownId = com[0]["SUP_DOWN_ID"];
    crmComId = com[0]["CRM_COM_ID"];
    let crmComName = com[0]["CRM_COM_NAME"];

    let contact = rstAll[1];
    if (contact.length == 0) {
        $Tip("没有联系人");
        return;
    }
    let crmCusId = contact[0]["CRM_CUS_ID"];

    if (!contact[0]["ADM_ID"]) {
        let syncOk = await new Promise((resolve) => {
            var u = EWA.CP + "/business/sync_b2b/push_sup_main.jsp?sup_id=" + supDownId + "&op=PUSH";
            $J1(u, function(rst) {
                if (rst && rst.RST) {
                    return resolve(true);
                } else {
                    return resolve(false);
                }
            })
        });
        if (!syncOk) {
            $Tip("帐号开通失败，请联系管理员");
            return;
        }

        await new Promise((resolve) => {
            let ewa = EWA.F.FOS["@sys_frame_unid"];
            let u2 = ewa.getUrlClass();
            u2.RemoveEwa();
            u2.AddParameter("xmlname", "/business/crm/sales_crm.xml");
            u2.AddParameter("ITEMNAME", "CRM_CUS.F.login");
            u2.AddParameter("EWA_AJAX", "json_all");
            u2.AddParameter("CRM_CUS_ID", crmCusId);
            $J(u2.GetUrl(), function() {
                return resolve();
            });
        });

        //获取代理和联系人信息
        let rstAll2 = await new Promise((resolve) => {
            u1.AddParameter("SUP_DOWN_ID", supDownId);
            $J(u1.GetUrl(), function(rst) {
                return resolve(rst);
            });
        });
        contact = rstAll2[1];
        if (contact.length == 0) {
            $Tip("没有联系人");
            return;
        }
    }

    let admId = contact[0]["ADM_ID"];
    if (!admId) {
        $Tip("获取联系人登录帐号失败");
        return;
    }

    let crmCusName = contact[0]["CRM_CUS_NAME"];
    if(!validTime){//无有效期限制
        var u = EWA.CP + "/app-2017/crm/create-agent-login-qrcode.jsp?SUP_ID=" + supDownId + "&CRM_COM_ID=" + crmComId + "&ADM_ID=" + admId;
        $J(u, function(rst) {
            if (!rst.RST) {
                alert(rst.ERR);
                return;
            }
            var u = rst.URL;
            var img = EWA.CP + "/back_admin/common/qrcode.jsp?msg=" + u.toURL();
            var s = "<div style='text-align:center'><img width=260 src='" + img + "'>" +
                "<div style='margin:20px auto 0 auto;font-size:14px'>" + crmComName + "<br>" + crmCusName + "</div>" +
                "<div style='margin:20px auto 0 auto;font-size:16px'><a target='_blank' href='" + img +
                "' download='" + crmComName + "(" + crmCusName + ").jpg'>下载二维码</a></div></div>";
            window.top.$DialogHtml(s, '代理登录二维码', 300, 400);
        });
    }else{
        let tip=crmComName;
        if(crmComName!=crmCusName){
            tip+="<br>"+crmCusName;
        }
        let imgName=crmCusName;
        let uf=ewa.getUrlClass();
        uf.AddParameter("EWA_AJAX", "json");
        uf.AddParameter("EWA_ACTION", "getFP");
        let mins; //默认有效期为分钟数
        if(isNaN(validTime)){
            if(validTime.indexOf("d")){//天数
                mins=validTime.replace("d","")*1440;
            }
        }else{
            mins=validTime*1;
        }
        /*
        if(mins>1440){
            tip+="，有效期"+(mins/1440)+"天";
        }else{
            tip+="，有效期"+mins+"分钟";
        }
        */
        uf.AddParameter("mins",mins);
        uf.AddParameter("adm_id",admId);
        uf.AddParameter("SUP_ID",supDownId);
        let fpData=await new Promise(resolve=>{
            $J1(uf.GetUrl(),function(rst){
               return resolve(rst[0]);
            });
        });
        let fpUid=fpData.FP_UNID;
        let fpCode=fpData.FP_VALIDCODE;
        targetUrl="@EWA.CP/customer/study-tour/agent.jsp?fpuid="+fpUid+"&fpcode="+fpCode;
        let u3=new EWA_UrlClass("/");
		u3.AddParameter("target_url",targetUrl);
		u3.AddParameter("convert_short_url",1);
		u3.AddParameter("tip",tip);
		u3.AddParameter("img_name",imgName);
		let paras=u3.GetParas();
        EWA.UI.Dialog.OpenFrame("@sys_frame_unid","/business/common/tools.xml","QRCODE.F.N",false,paras);
    }
}

(function() {
    var ewa = EWA.F.FOS["@sys_frame_unid"];

    ewa.valid_targets = ["CONTACTS", "COOP_PLAN", "BOOKING", "QUERIES", "ENQ_OPS"
        , "CONTRACTS", "GRP_PROGRESSES", "CUST_PROGRESSES", "CF_PROGRESS"
        , "QA_NEW"];
    //展开显示联系记录
    ewa.AddPreRow(
        function(frameUnid, tr, key, newTr, evt) {
            var target = evt.target;
            var cur_target_id = "";
            var target_obj;
            for (var i = 0; i < this.valid_targets.length; i++) {
                var id = this.valid_targets[i];
                if ($(target).hasClass("ewa-col-" + id)) { //点击td
                    target_obj = target;
                    cur_target_id = id;
                } else if (target.id == id) { //点击元素
                    target_obj = $(target).parent()[0];
                    cur_target_id = id;
                }
                if (cur_target_id) {
                    break;
                }
            }
            var u1 = new EWA_UrlClass(ewa.Url);
            u1.AddParameter("EWA_AJAX", "INSTALL");
            u1.AddParameter("BY_CRM_COM_ID", key);
            var sup_id = 0;
            sup_id = $(tr).find("a#CRM_COM_NAME").attr("data-sup-id");
            if (cur_target_id == "CONTACTS") {
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("XMLNAME", "/business/crm/sales_crm.xml");
                u1.AddParameter("ITEMNAME", "CRM_RECORD.ListFrame.Modify");
            } else if (cur_target_id == "COOP_PLAN" || cur_target_id == "BOOKING") {
                u1.AddParameter("COOP_PLAN", "1");
                u1.AddParameter("XMLNAME", "@xmlname");
                u1.AddParameter("ITEMNAME", "index-sub-ENQ_MAIN.LF.M");
            } else if (cur_target_id == "QUERIES") {
                u1.AddParameter("XMLNAME", "@xmlname");
                u1.AddParameter("ITEMNAME", "index-sub-ENQ_MAIN.LF.M");
            } else if (cur_target_id == "ENQ_OPS") {
                u1.AddParameter("ENQ_OPS", "1");
                u1.AddParameter("XMLNAME", "@xmlname");
                u1.AddParameter("ITEMNAME", "index-sub-ENQ_MAIN.LF.M");
            } else if (cur_target_id == "GRP_PROGRESSES" || cur_target_id == "CUST_PROGRESSES") {
                if (!sup_id) {
                    $Tip("未签约客户");
                    return;
                }
                u1.AddParameter("GRP_PROGRESSES", "1");
                u1.AddParameter("BY_SUP_ID", sup_id);
                u1.AddParameter("XMLNAME", "@xmlname");
                u1.AddParameter("ITEMNAME", "index-sub-GRP_MAIN.LF.M");
            } else if (cur_target_id == "CONTRACTS") {
                if (!sup_id) {
                    $Tip("未签约客户");
                    return;
                }
                u1.AddParameter("BY_SUP_ID", sup_id);
                u1.AddParameter("BY_FILE_TYPE", "PACT1");
                u1.AddParameter("XMLNAME", "@xmlname");
                u1.AddParameter("ITEMNAME", "index-CURRENCY_FILE.LF.V");
            } else if(cur_target_id=="CF_PROGRESS"){
                u1.AddParameter("CRM_COM_ID",key);
                u1.AddParameter("CURRENT_YEAR",'@CURRENT_YEAR');
                u1.AddParameter("BY_CRM_COM_ID",1);
                u1.AddParameter("XMLNAME","/business/crm/crm_feedback.xml");
                u1.AddParameter("ITEMNAME","CRM_FEEDBACK.LF.M");  
            } else if(cur_target_id=="QA_NEW"){
                u1.AddParameter("REF_ID",sup_id);
                u1.AddParameter("REF_TAG","QA_REF_SUP_MAIN");
                u1.AddParameter("HID_COUNTRY",1);
                u1.AddParameter("XMLNAME","/business/oa/qa.xml");
                u1.AddParameter("ITEMNAME","WEB_QA_MAIN.LF.M");  
            } else {
                return;
            }

            var cnt_td = newTr.cells[0];
            $(cnt_td).addClass('add-pre-row');

            $(target_obj).addClass("customer-add-row-cur-td");
            var ajax_url = u1.GetUrl();
            $Install(ajax_url, cnt_td.id, function() {
                // console.log('install ok');
            });
        }
    );
    ewa.AddPreRowCheck = function(tr, key, evt) {
        $("#EWA_LF_" + this.Id + " .customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
        var target = evt.target;
        for (var i = 0; i < this.valid_targets.length; i++) {
            var id = this.valid_targets[i];
            if ($(target).hasClass("ewa-col-" + id) || target.id == id) {
                return true;
            }
        }
        if (this.prevTr) {
            $(this.prevTr).remove();
            this.prevTr = null;
        }

        return false;
    };
    ewa.AddPreRowCloseEvent = function(frameUnid, tr, key, newTr, evt) {
        $(evt.target).parentsUntil("tr").parent().find(".customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
    }

    function getObj(exp){
		return exp?$('#EWA_LF_@sys_frame_unid').find(exp):$('#EWA_LF_@sys_frame_unid');
	}


    ewa.ReloadAfter = function() {
        ewa.Merge('QA_ALL','QA_NEW','/'); 

        //单元格添加title
        let arr_fid="COOP_PLAN,BOOKING,QUERIES,ENQ_OPS,GRP_PROGRESSES,CUST_PROGRESSES".split(",");
        let arr_title=[];
        for(let i=0;i<arr_fid.length;i++){
            let t=getObj(".ewa-lf-header #"+arr_fid[i]).attr("title");
            if(t){
                arr_title.push({"field_name":arr_fid[i],"title":t});
            }
            for(let i=0;i<arr_title.length;i++){
                getObj("tr.ewa-lf-data-row td.ewa-col-"+arr_title[i].field_name).attr("title",arr_title[i].title);
            }
        }

        //添加下一行事件元素添加样式
        for (var i = 0; i < this.valid_targets.length; i++) {
            //$("#EWA_LF_" + this.Id + " .ewa-lf-data-row .ewa-col-" + this.valid_targets[i])
            //    .addClass("customer-add-row-td");
            $("#EWA_LF_" + this.Id + " .ewa-lf-data-row .ewa-col-" + this.valid_targets[i])
                .addClass("customer-add-row-td");
        }
        //绑定按钮事件
        //打开客户面板
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butPanel]").on("click", function() {
            var name = $(this).attr("data-crm-com-name");
            var id = $(this).attr("data-crm-com-id");
            var u = "@EWA.CP/business/sales/agent-index.jsp?T=10&crm_com_id=" + id;
            if (top != window && top.AddTab) {
                top.AddTab(u, name);
            } else {
                window.open(u);
            }
        });
        //查看修改客户信息
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butModify]").on("click", function() {
            var id = $(this).attr("data-crm-com-id");
            EWA.UI.Dialog.OpenReloadClose("@SYS_FRAME_UNID",
                "|business|crm|sales_crm.xml", "CRM_COM_NEW.Frame.Modify",
                false,
                "EWA_MTYPE=M&EWA_REDRAW=1&METHOD=DJ&CRM_COM_ID=" + id);
        });
        //添加查看链接文字内容
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-col-linkView a").html(ewa.Resources.lkView.GetInfo());

        //添加联系记录
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butAddContact]").on("click", function() {
            var id = $(this).attr("data-crm-com-id");
            var p = 'EWA_MTYPE=N&CRM_COM_ID=' + id + "&COM_ID=" + id;
            EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
                '|business|crm|sales_crm.xml', 'CRM_RECORD.Frame.NewModify', false, p);
        });

    }
    ewa.ReloadAfter();
})();

