Set.Sql:
-- EWA_SQL_SPLIT_NO SELECT TOP 1 BAS_TAG CURRENT_YEAR FROM BAS_TAG WHERE BAS_TAG_GRP='YEARS' AND BAS_TAG_PARA1='CURRENT' ORDER BY BAS_TAG DESC ;
DELETE FROM SUP_HAS_GROUP WHERE 1=1;
INSERT INTO SUP_HAS_GROUP(SUP_DOWN_ID,LAST_TIME,GRPS,OP_IDS) SELECT A.SUP_DOWN_ID,getdate(), COUNT(*) GRPS ,stuff((select ','+cast(xa.OP_ID as varchar(20)) from grp_main xa inner join crm_conn xb on xa.SUP_DOWN_ID=xb.SUP_DOWN_ID inner join adm_user xc on xa.op_id=xc.adm_id and xc.ADM_USR_STA_TAG='OK' and xc.ADM_OP='COM_YES' where xb.SUP_DOWN_ID=A.SUP_DOWN_ID AND xa.GRP_STATE = 'USED' AND xa.grp_code='' AND xa.GRP_PID IS NULL AND xa.SUP_ID=@G_SUP_ID AND NOT xa.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') group by xa.OP_ID order by count(1) desc for xml path('') ),1,1,'') OP_IDS FROM GRP_MAIN A inner join enq_main b on a.GRP_ID=b.GRP_ID and b.ENQ_DEFAULT='COM_YES' WHERE A.GRP_STATE = 'USED' AND a.grp_code='' AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND DATEADD(d,30+isnull(day_num,0),GRP_SDATE)>GETDATE() AND NOT A.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') GROUP BY A.SUP_DOWN_ID ;
SELECT * FROM ( SELECT CASE WHEN BAS_TAG_NAME IS NULL THEN '发展中'ELSE '已签约' END AS TAG , DEP_NAME , CRM_CONN_TAG , V.* , isnull(cc.sup_down_id,0) r_sup_id , CASE WHEN cc.SUP_DOWN_ID IS NULL THEN 'SIGN_NO' ELSE 'SIGN_YES' END SIGN , A0.ADM_NAME , CONTACTS.CONTACTS , COOP_PLAN.COOP_PLAN , BOOKING.BOOKING , QUERIES.QUERIES , ENQ_OPS.ENQ_OPS , CUST_PROGRESSES.* , isnull(CUST_PROGRESSES.BILL_GRPS,0)+isnull(UN_BILL_GRPS.UN_BILL_GRPS,0) GRP_PROGRESSES , BILL_RECEIVABLE - BILL_RECEIVED as BILL_UNPAY , HISTORY.* , ct.CONTRACTS , case when cf.CF_ID is null then 'COM_NO' else 'COM_YES' end CF_NEED , cf.CF_YEAR , isnull(cf.CF_PROGRESS,0) CF_PROGRESS , cf.CF_MDATE , CC.ADM_ID SALE_ID , QA.QA_ALL , QA.QA_NEW , OP.OP_IDS FROM CRM_COM V left join CRM_FEEDBACK cf on v.CRM_COM_ID=cf.CRM_COM_ID and cf.CF_HIS='N' and cf.CF_YEAR=@CURRENT_YEAR LEFT JOIN CRM_CONN CC ON V.CRM_COM_ID = CC.CRM_COM_ID AND CC.SUP_UP_ID = @G_SUP_ID LEFT JOIN BAS_TAG B1 ON B1.BAS_TAG = CRM_CONN_TAG LEFT JOIN ADM_USER A0 ON isnull(cc.ADM_ID,v.ADM_ID) = A0.ADM_ID LEFT JOIN ADM_DEPT A1 ON A1.DEP_ID = A0.ADM_DEP_ID LEFT JOIN ( SELECT B.CRM_COM_ID AS ID1, COUNT(*) AS CONTACTS FROM CRM_RECORD A INNER JOIN CRM_CUS B ON A.CRM_CUS_ID = B.CRM_CUS_ID WHERE A.SUP_ID=@G_SUP_ID GROUP BY B.CRM_COM_ID ) CONTACTS ON V.CRM_COM_ID = CONTACTS.ID1 LEFT JOIN ( SELECT A.SUP_DOWN_ID ID2, COUNT(*) COOP_PLAN FROM GRP_MAIN A WHERE GRP_STA='SCM_GRP_STA_NEW' AND A.GRP_STATE = 'USED' AND a.grp_code='' AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND NOT A.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') AND A.GRP_SDATE>@SYS_DATE GROUP BY A.SUP_DOWN_ID ) COOP_PLAN ON CC.SUP_DOWN_ID = COOP_PLAN.ID2 -- 合作计划 LEFT JOIN ( SELECT A.SUP_DOWN_ID ID2, SUM(isnull(b.PEOPLE_NUM,0)+isnull(b.HEAD_NUM,0)) BOOKING FROM GRP_MAIN A inner join ENQ_MAIN b on a.grp_id=b.grp_id and b.ENQ_DEFAULT='COM_YES' WHERE GRP_STA='SCM_GRP_STA_NEW' AND A.GRP_STATE = 'USED' AND a.grp_code='' AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND NOT A.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') AND A.GRP_SDATE>@SYS_DATE GROUP BY A.SUP_DOWN_ID ) BOOKING ON CC.SUP_DOWN_ID = BOOKING.ID2 -- 预订人数 LEFT JOIN ( SELECT A.SUP_DOWN_ID ID2, COUNT(*) QUERIES FROM GRP_MAIN A WHERE GRP_STA='SCM_GRP_STA_NEW' AND A.GRP_STATE = 'USED' AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND NOT A.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') GROUP BY A.SUP_DOWN_ID ) QUERIES ON CC.SUP_DOWN_ID = QUERIES.ID2 -- 询价单 LEFT JOIN ( SELECT b.SUP_DOWN_ID ID3, COUNT(*) ENQ_OPS FROM ENQ_MAIN a inner join GRP_MAIN b on a.GRP_ID = b.GRP_ID and b.GRP_STA='SCM_GRP_STA_NEW' and a.ENQ_DEFAULT='COM_YES' AND B.GRP_STATE = 'USED' AND b.grp_code='' AND B.GRP_PID IS NULL AND B.SUP_ID=@G_SUP_ID AND NOT b.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') where FLOW_STATE in ('ENQ_STAR', 'ENQ_OP') GROUP BY b.SUP_DOWN_ID -- 报价列表 ) ENQ_OPS ON ENQ_OPS.ID3 = CC.SUP_DOWN_ID LEFT JOIN ( SELECT B.RELATE_SUP_ID ID5 , COUNT(*) AS BILL_GRPS -- 新团数量 , SUM(B.BILL_PEOPLE_NUM) AS CUST_PROGRESSES , SUM(B.BILL_RECEIVABLE) AS BILL_RECEIVABLE , SUM(B.BILL_RECEIVED) AS BILL_RECEIVED , SUM(B.BILL_EXIT_NUM) AS EXITS -- 退团人数 , SUM(B.BILL_EXIT_MONEY) AS BILL_EXIT_MONEY , SUM(B.BILL_DISCOUNT_NUM) AS DISCOUNTS -- 优惠人数 , SUM(B.BILL_DISCOUNT_MONEY) AS BILL_DISCOUNT_MONEY , SUM(B.BILL_EXCHANGE_OUT_NUM) AS CHANGES -- 转团人数 , SUM(B.BILL_EXCHANGE_IN_NUM) AS BILL_EXCHANGE_IN_NUM , SUM(B.BILL_REFUND_NUM) AS BILL_REFUND_NUM , SUM(B.BILL_REFUND_MONEY) AS BILL_REFUND_MONEY FROM GRP_MAIN A INNER JOIN GRP_BILL B ON A.GRP_ID = B.GRP_ID AND A.GRP_STA='SCM_GRP_STA_UNENQ' AND A.GRP_STATE = 'USED' AND a.grp_code='' AND (A.CLAC_STATUS!='FINALLY_CLOSE' ) AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND NOT A.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') GROUP BY B.RELATE_SUP_ID ) CUST_PROGRESSES ON CUST_PROGRESSES.ID5 = CC.SUP_DOWN_ID left JOIN( select count(1) UN_BILL_GRPS,A.SUP_DOWN_ID from GRP_MAIN A where A.GRP_STA='SCM_GRP_STA_UNENQ' AND A.GRP_STATE = 'USED' AND a.grp_code='' AND (A.CLAC_STATUS!='FINALLY_CLOSE' ) AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND NOT A.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') AND not exists(select 1 from GRP_BILL x where a.GRP_ID=x.GRP_ID and a.SUP_DOWN_ID=x.RELATE_SUP_ID) group by A.SUP_DOWN_ID ) UN_BILL_GRPS on UN_BILL_GRPS.SUP_DOWN_ID=cc.SUP_DOWN_ID LEFT JOIN ( select c.RELATE_SUP_ID AS ID6 , sum(c.SETTL_INCOME) AS HIS_RECEIVED , sum(c.SETTL_MARGIN) AS HIS_PROFIT , sum(SETTL_NUM_TOTAL) AS CUST_HISTORIES , count(*) AS GRP_HISTORIES from GRP_MAIN a inner join GRP_SETTL b on a.GRP_SETTL_UNID = b.GRP_SETTL_UNID and a.GRP_ID = b.GRP_ID inner join GRP_SETTL_SALES c on b.GRP_SETTL_ID = c.GRP_SETTL_ID where a.CLAC_STATUS ='FINALLY_CLOSE' AND A.SUP_ID=@G_SUP_ID and a.GRP_STATE='USED' AND NOT A.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') group by c.RELATE_SUP_ID ) HISTORY ON HISTORY.ID6 = CC.SUP_DOWN_ID LEFT JOIN ( select COUNT(1) CONTRACTS,a.RELATE_SUP_ID from CURRENCY_FILE a inner join GRP_MAIN b on a.GRP_ID=b.GRP_ID where a.FILE_TYPE='PACT1' and b.GRP_STATE='USED' AND b.grp_code='' and PIC_PHY_PATH IS NOT NULL AND PIC_PHY_PATH != '' and STATE='USED' and a.SUP_ID=@G_SUP_ID AND NOT b.GRP_TYPE in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC','GRP_TYPE_BMYX','GRP_TYPE_BMYX_COS') group by a.RELATE_SUP_ID ) ct on cc.SUP_DOWN_ID=ct.RELATE_SUP_ID --团合同数量 LEFT JOIN ( SELECT REF_ID QA_SUP_ID, sum(case when wqm.QA_STATUS != 'QA_STATUS_DEL' then 1 else 0 end) QA_ALL, sum(case when wqm.QA_STATUS = 'QA_STATUS_NEW' then 1 else 0 end) QA_NEW from WEB_QA_MAIN wqm where REF_TAG = 'QA_REF_SUP_MAIN' group by REF_ID ) QA ON QA.QA_SUP_ID=cc.SUP_DOWN_ID INNER JOIN SUP_HAS_GROUP OP ON CC.SUP_DOWN_ID = OP.SUP_DOWN_ID -- 运行的团，已回团30天以内 WHERE V.SUP_ID=@G_SUP_ID ) AS TE WHERE USE_STATE='USED' order by CRM_COM_CODE desc, BILL_RECEIVED desc,CRM_COM_ID DESC

select top 1 FP_UNID TMP_FP_UNID,FP_VALIDCODE TMP_FP_VALIDCODE from WEB_USER_FPWD where FP_TYPE='WX_ADM_LOGIN' and USR_ID=@adm_id and FP_REF_TABLE='SUP_MAIN/QR_LOGIN' and FP_REF_ID=@SUP_ID order by FP_EDATE desc ;
delete WEB_USER_FPWD where FP_TYPE='WX_ADM_LOGIN' and USR_ID=@adm_id and FP_REF_TABLE='SUP_MAIN/QR_LOGIN' and FP_REF_ID=@SUP_ID ;
select @sys_unid TMP_FP_UNID ,substring(convert(varchar(36),newid()),1,6) TMP_FP_VALIDCODE where @TMP_FP_UNID is null ;
INSERT INTO WEB_USER_FPWD(FP_UNID, USR_ID, FP_CDATE , FP_EDATE, FP_UDATE, FP_VALIDCODE , FP_TYPE, FP_REF_TABLE, FP_REF_ID ) values(@TMP_FP_UNID,@adm_id,getdate() ,dateadd(MINUTE,convert(int,@mins),getdate()),null,@TMP_FP_VALIDCODE ,'WX_ADM_LOGIN','SUP_MAIN/QR_LOGIN',@SUP_ID) ;
select FP_UNID,FP_VALIDCODE,convert(varchar(19),FP_EDATE,120) FP_EDATE from WEB_USER_FPWD where FP_UNID=@TMP_FP_UNID;

Set.Bottom:
$(function() {
    var ewa = EWA.F.FOS["@sys_frame_unid"];
    ewa.valid_targets = ["CONTACTS"];

    EWA.F.FOS["@sys_frame_unid"].AddPreRowCheck = function(tr, key, evt) {
        if ("@NOT_EXPAND" != "") { //不展开
            return false;
        }
        return true;
    };
    ewa.AddPreRow(function(frameUnid, tr, key, newTr, evt) {
        var u1 = new EWA_UrlClass(ewa.Url);
        u1.RemoveEwa();
        u1.AddParameter("SUP_ID", key);
        u1.SetRoot("@ewa.cp/business/supply/supply-index.jsp?in_grp=1");
        var cnt_td = newTr.cells[0];
        var ajax_url = u1.GetUrl();
        $Install(ajax_url, cnt_td, function() {
            // console.log('install ok');
        });
    });

    ewa.ReloadAfter = function() {
        //添加下一行事件元素添加样式
        for (var i = 0; i < this.valid_targets.length; i++) {
            $("#EWA_LF_" + this.Id + " .ewa-lf-data-row .ewa-col-" + this.valid_targets[i]).addClass("customer-add-row-td");
        }
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butPanel]").on("click", function() {
            var sup_id = $(this).attr("data-sup-id");
            var crm_com_id = $(this).attr("data-crm-com-id");
            var u1 = "@ewa.cp/business/supply/supply-index.jsp?TP=2&CRM_COM_ID=" + crm_com_id + "&SUP_ID=" + sup_id + "&REF_ID=" + sup_id;
            if (top.AddTab && top != window) {
                top.AddTab(u1);
            } else {
                window.open(u1);
            }
        });
        //查看修改客户信息
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butModify]").on("click", function() {
            var sup_id = $(this).attr("data-sup-id");
            var crm_com_id = $(this).attr("data-crm-com-id");
            var paras = "EWA_MTYPE=M&EWA_REDRAW=1&SUP_ID=" + sup_id + "&CRM_COM_ID=" + crm_com_id;
            EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
                '/business/crm/supplier.xml', 'CRM_COM_SUP.EASY.F.M', false, paras);
        });
        //添加查看链接文字内容
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-col-linkView a").html(ewa.Resources.lkView.GetInfo());

        //添加联系记录
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butContact]").on("click", function() {
            var crm_com_id = $(this).attr("data-crm-com-id");
            var p = 'EWA_MTYPE=N&CRM_COM_ID=' + crm_com_id + "&COM_ID=" + crm_com_id;
            EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
                '|business|crm|sales_crm.xml', 'CRM_RECORD.Frame.NewModify', false, p);
        });
    }
    ewa.ReloadAfter();

    ewa.ext_convert = function() {
        //let paras = 'EWA_MTYPE=M&crm_com_id=' + crm_com_id+'&SUP_ID='+sup_id;
        //console.log(paras)
        let paras = 'EWA_MTYPE=M';
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '/business/crm/supplier.xml', 'CRM_2_SUP.F.M', false, paras);
    }
});
