Set.Sql:
select '已分配销售不能删除' EWA_ERR_OUT WHERE exists( select 1 from CRM_COM WHERE CRM_COM_ID = @CRM_COM_ID and ADM_ID is not null) or exists( select 1 from crm_conn where CRM_COM_ID=@CRM_COM_ID ) ;
select '只能删除自己或下属添加的客户' EWA_ERR_OUT where not exists (select 1 from CRM_COM where CRM_COM_ID = @CRM_COM_ID and (AUS_TAID = @G_ADM_ID or AUS_TAID in (@G_SUB_IDS_SPLIT))) ;
UPDATE CRM_COM SET USE_STATE='DEL' ,CRM_COM_MDATE=@SYS_DATE ,M_ADM_ID = @G_ADM_ID WHERE CRM_COM_ID = @CRM_COM_ID and (AUS_TAID = @G_ADM_ID or AUS_TAID in (@G_SUB_IDS_SPLIT)) and ADM_ID is null and not exists( select 1 from crm_conn where CRM_COM_ID=@CRM_COM_ID ) and sup_id=@g_sup_id

