        top.AddTab(url);
    }

    ewa.ReloadAfter = function() {
        var tb = $('#EWA_LF_@SYS_FRAME_UNID')
        //添加下一行事件元素添加样式
        if (!"@disabled_unfold") { // 阻止展开
            for (var i = 0; i < this.valid_targets.length; i++) {
                $("#EWA_LF_" + this.Id + " .ewa-lf-data-row .ewa-col-" + this.valid_targets[i]).addClass("customer-add-row-td");
            }
        }
        //已报名Title，改为Students + Leaders
        tb.find(".ewa-col-PAX #PAX").each(function() {
            var title = $(this).attr("data-pax-title");
            $(this).attr("title", title).parent().attr("title", title);
        });


        // 锁定前三列
        // tb.find(".ewa-col-GRP_HY_CODE").css({"position":"sticky","z-index":2,"left":"1px"});
        // let qrcodeLeft=tb.find(".ewa-col-GRP_HY_CODE").width()+4;
        // tb.find(".ewa-col-qrcode").css({"position":"sticky","z-index":2,"left":qrcodeLeft+"px"});
        // let grpNameLeft=qrcodeLeft+tb.find(".ewa-col-qrcode").width()+3;
        // tb.find(".ewa-col-GRP_NAME").css({"position":"sticky","z-index":2,"left":grpNameLeft+"px"});

        ewa.stickyColumns(4);

        //绑定按钮事件
        //打开项目设计或打开团控制面板
        tb.find("input[id=butPanel]").on("click", function() {
            let tr = $(this).closest("tr");
            let u;
            if (tr.data("grp-code") == "GRP_GYAP_DOC") {
                u = "@EWA.CP/business/group/design.jsp?IS_DESIGN=1&GRP_GYAP_ID=" + tr.data("grp-gyap-id");
            } else {
                var grp_id = $(this).attr("data-grp-id");

                var grp_hy_code = $(this).attr("data-grp-hy-code");
                //var enq_id = $(this).attr("data-enq-id");
                var nums1 = $(this).attr("data-ppnum");
                var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
                var p = 'grp_id=' + grp_id + '&nums=' + nums1 +
                    '&grp_hy_code=' + grp_hy_code + '&xml=grp_detail.xml';
                if (u1.GetParameter("T")) {
                    p += "&T=" + u1.GetParameter("T");
                } else if ("@VIEW_ACL") {
                    p += "&T=12";
                }
                u = "@ewa.cp/business/group/grp-index.jsp?" + p;
            }
            if (top.AddTab && top != window) {
                top.AddTab(u);
            } else {
                window.open(u);
            }
        });

        //我关注的团onclick事件，在我关注的团里时点击后延时100ms刷新列表
        ewa.ext_fav = function(obj) {
            if (!"@only_my_fav_grp") {
                return;
            }
            let ipt = $(obj).find("input");
            if (!ipt.prop("checked")) {
                window.setTimeout(function() {
                    ewa.Reload();
                }, 100);
            }
        }

        //显示团报名二维码(小程序)
        /*
        tb.find(".ewa-col-qrcode a").on("click", function() {
            var objParent = $(this).parent();
            var grp_id = objParent.attr("data-grp-id");
            grpIds.push(grp_id);
            var grp_hy_code = objParent.attr("data-grp-hy-code");
            var grp_name = objParent.attr("data-grp-name");
            var grp_run_model = objParent.attr("data-grp-run-model");

            var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            u1.RemoveEwa();
            u1.AddParameter("GRP_ID", grp_id);
            u1.AddParameter("GRP_HY_CODE", grp_hy_code);
            u1.AddParameter("GRP_NAME", grp_name);
            var u = EWA.CP + "/app-2017/crm/enroll.jsp?FROM=customer&" + u1.GetParas();
            if (grp_run_model == 'GRP_RUN_SINGLE') {
                u += "&SID=" + $(this).closest("tr").attr("data-sup-down-id");
            }
            var dia = window.top.$DialogInstall(u);
        });
        */


        var grpIds = [];
        var mapGrp = {};
        tb.find('.ewa-lf-data-row').each(function() {
            var grp_id = $(this).attr('ewa_key');
            grpIds.push(grp_id);
            mapGrp[grp_id] = $(this);
        });

        var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "LoadData");
        u1.AddParameter("ewa_ajax", "json_all");
        var data = {
            "ids_split": grpIds.join(",")
        };
        var u = u1.GetUrl();
        $JP(u, data, function(rst) {

            var airData = rst[0];
            var map = {};
            for (var n in airData) {
                var d = airData[n];
                var grpid = d.GRP_ID;
                if (!map[grpid]) {
                    map[grpid] = [];
                }
                map[grpid].push("<div title=\"" + d.SUP_NAME + "\">" + d.SUP_NAME + "</div>");
            }
            for (var gid in map) {
                var arr = map[gid];
                var tr = mapGrp[gid];
                if (!tr) {
                    console.log('找不到grp_id=' + gid + "的tr");
                    continue;
                }
                tr.find('[name=CP_AIR_TICKET]').html(arr.join(""));
            }
        });

        getObj("tr.ewa-lf-data-row").each(function() {
            let formId = $(this).attr("data-grp-form-id");
            if (formId && formId != "-1" && formId != "0") {
                let grpSta = $(this).attr("data-grp-sta");
                if (grpSta == "SCM_GRP_STA_NEW") {
                    $(this).find("#SUP_NAME").css({
                        "color": "#f60"
                    }).attr("title", "客户提交报价需求");
                }
            }
        });

        getObj("tr.ewa-lf-data-row .ewa-col-PD_NAME a[title]").each(function() {
            $(this).html("海报");
        });

    }
    ewa.ReloadAfter();

    function getObj(exp) {
        return exp ? $('#EWA_LF_@sys_frame_unid').find(exp) : $('#EWA_LF_@sys_frame_unid');
    }
    ewa.ext_AddEnqAI = function(){
        const u = "@ewa.cp/ewa.jsp?XMLNAME=/business/ai/tpl.xml&ITEMNAME=Q_ENQ_MAIN.F.stream2";
        if(top.AddTab){
            top.AddTab(u);
        } else {
            window.open(u);
        }
    };
    // 新建报价
    ewa.ext_AddEnq = function() {
        var x = "business/group/grp.xml";
        var i = "ENQ_MAIN.Frame.NewModify";
        var p = "EWA_MTYPE=N&EWA_REDRAW=1&METHOD=DJ&SALES=@g_adm_id&INIT_W=990px&GRP_HY_CODE=Auto&CRM_ID=@CRM_COM_ID&fromtempid=";
        if ("@gxjykc" != "") {
            let p2 = "GRP_TYPE=GRP_TYPE_GXJYKC&HEAD_NUM=0";
            p = p2 + "&" + p;
        } else {
            let u1 = ewa.getUrlClass();
            let grpType = u1.GetParameter("GRP_TYPE");
            if (grpType) {
                p += "&GRP_TYPE=" + grpType;
            }
        }
        EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid", x, i, false, p);
    }

    // 新增或导入项目
    ewa.ext_AddGyapDoc = function() {
        let u = "@EWA.CP/robert/gyap-project/design.jsp?IS_DESIGN=1&NEW_OR_IMPORT=1&IMPORT_GRP=N";
        if (top.AddTab && top != window) {
            top.AddTab(u);
        } else {
            window.open(u);
        }
    }

    ewa.ext_EasyEnq = function(grpId) {
        var x = "/business/enq/enq.xml";
        var i = "Q_ENQ.F.Easy_from_grp";
        var p = "EWA_MTYPE=N&EWA_REDRAW=1&METHOD=DJ&SALES=@g_adm_id&INIT_W=990px&GRP_HY_CODE=Auto";

        let u1 = ewa.getUrlClass();
        let grpType = u1.GetParameter("GRP_TYPE");
        if (grpType == 'GRP_TYPE_AIR_TICKET') {
            x = "/business/enq/enq.xml";
            i = "Q_ENQ.F.AIR_TICKET";
            p = "EWA_MTYPE=N";
            p += "&OP_ID=23"; // 机票默认OP 刘星
        }
        if (grpId) {
            p += "&FROM_GRP_ID=" + grpId;
        } else {
            if (grpType) {
                p += "&GRP_TYPE=" + grpType;
            }
        }
        EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid", x, i, false, p);
    }

    // 复制项目到新报价
    ewa.ext_copyToEnq = function(grpGyapId) {
        if (!grpGyapId) {
            $Tip("没有项目信息");
            return;
        }
        this.ext_EasyEnq(grpGyapId);
    }
    // 报名二维码
    ewa.ext_EnrollQrcode = function(obj) {
        let tr = $(obj).closest("tr");
        let grpUnid = tr.attr("data-grp-unid");
        let grpHyCode = tr.find("#GRP_HY_CODE").text().trim();
        let grpName = tr.find("#GRP_NAME").text().trim();
        let supDownId = tr.attr("data-sup-down-id");
        let domain = location.host.indexOf('gdx') >= 0 ? "gdx8" : "www.gyap.org";
        let grpId = tr.attr("data-grp-id");
        let connId = tr.attr("data-conn-id");

        let targetUrl = "https://" + domain + "/" + (EWA.CP.split("/")[1]) +
            "/customer/study-tour/enrollframe.jsp?grp_unid=" + grpUnid;

        let tip = grpName + '<br>' + grpHyCode;
        let u3 = new EWA_UrlClass("/");
        u3.AddParameter("target_url", targetUrl);
        u3.AddParameter("convert_short_url", 1);
        u3.AddParameter("tip", tip);
        u3.AddParameter("img_name", grpHyCode);
        u3.AddParameter("show_adm_unid", 1);
        u3.AddParameter("I_Am_Recommender", 1);
        u3.AddParameter("recommender", 1);
        u3.AddParameter("SUP_DOWN_ID", supDownId);
        if (connId) {
            u3.AddParameter("REF_TABLE", "GRP_MAIN.ENROLL");
            u3.AddParameter("REF_ID", grpId);
            u3.AddParameter("CONN_ID", connId);
        }

        let paras = u3.GetParas();
        EWA.UI.Dialog.OpenFrame("create_qrcode", "/business/common/tools.xml", "QRCODE.F.N", false, paras);
    }
    if ('@ref_grp_id') {
        getObj("tr .ewa-col-qrcode a").css({
            "font-size": "20px"
        }).attr("title", "报名二维码");
    }

    // 报价二维码
    ewa.ext_enqQrcode = function() {
        let domain = location.host.indexOf('gdx') >= 0 ? "gdx8" : "www.gyap.org";
        let targetUrl = "@ewa.cp/cooperation/enq.jsp?sale_id=@g_adm_id";

        let tip = '报价二维码';
        let u3 = new EWA_UrlClass("/");
        u3.AddParameter("target_url", targetUrl);
        u3.AddParameter("convert_short_url", 1);
        u3.AddParameter("tip", tip);
