        //     $Tip("制作中");
        // }
    }
    ewa.openPosterTemplate=function(){
        let u="@EWA.CP/poster-design/pd-list.jsp?PD_TAG=CRM_COM";
        window.top.AddTab(u);
    }
    ewa.extSendMail=function(obj){
        let tr= $(obj).closest("tr")
        let email=tr[0].dataset.crmComEmail;
        let crmComId=tr.attr("ewa_key");
        let u1=ewa.getUrlClass();
        u1.RemoveEwa();
        //u1.AddParameter("XMLNAME","business/crm/mail_send.xml");
        //u1.AddParameter("ITEMNAME","MAIL_SEND.F.NM");
        u1.AddParameter("EWA_MTYPE","N");
        if(email){
            u1.AddParameter("TARGET_EMAIL",email);
        }
        u1.AddParameter("ms_ref","CRM_COM");
        u1.AddParameter("ms_ref_id",crmComId);
        u1.AddParameter("MS_LANG","zhcn");
        let paras=u1.GetParas();
        EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid","business/crm/mail_send.xml","MAIL_SEND.F.NM",false,paras);
    }

    ewa.valid_targets = ["CRM_COM_NAME","CONTACTS","CF_PROGRESS","SENT_NUM"
        , "QUERIES","CPS", "GRP_NUM","CLOSED_NUM","COS_NUM","CONTRACTS", "PROM_NUM"];
    //展开显示联系记录
    ewa.AddPreRow(function(frameUnid, tr, key, newTr, evt) {
        let target = evt.target;
        let cur_target_id = "";
        let target_obj;
        for (let i = 0; i < this.valid_targets.length; i++) {
            let id = this.valid_targets[i];
            if ($(target).hasClass("ewa-col-" + id)) { //点击td
                target_obj = target;
                cur_target_id = id;
            } else if (target.id == id) { //点击元素
                target_obj = $(target).parent()[0];
                cur_target_id = id;
            }
            if (cur_target_id) {
                break;
            }
        }
        if(!cur_target_id){
            cur_target_id="CRM_COM_NAME";
            target_obj=$(tr).find(".ewa-col-"+cur_target_id);
        }
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.AddParameter("EWA_AJAX", "INSTALL");
        u1.AddParameter("BY_CRM_COM_ID", key);
        u1.AddParameter("EWA_FRAME_UNID_PREFIX",key+"_");
        let sup_id = 0;
        sup_id = $(tr).attr("data-r-sup-id");
        if (cur_target_id == "CRM_COM_NAME") {
            u1.RemoveEwa();
            u1.AddParameter("crm_com_id", key);
            u1.AddParameter("EWA_FRAME_UNID_PREFIX",key+"_");
            if(sup_id && sup_id!="0"){
                u1.AddParameter("SUP_ID", sup_id);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
            }
            u1.SetRoot("@ewa.cp/business/sales/agent-index-2025.jsp?in_grp=1");
            u1.AddParameter("SUP_ID", sup_id);
        } else if (cur_target_id == "CONTACTS") {
            u1.AddParameter("CRM_COM_ID", key);
            u1.AddParameter("XMLNAME", "/business/crm/sales_crm.xml");
            u1.AddParameter("ITEMNAME", "CRM_RECORD.ListFrame.Modify");
        } else if (cur_target_id == "CF_PROGRESS") {
            u1.AddParameter("CRM_COM_ID", key);
            u1.AddParameter("CURRENT_YEAR", '@CURRENT_YEAR');
            u1.AddParameter("BY_CRM_COM_ID", 1);
            u1.AddParameter("XMLNAME", "/business/crm/crm_feedback.xml");
            u1.AddParameter("ITEMNAME", "CRM_FEEDBACK.LF.M");
        } else if (cur_target_id == "SENT_NUM") {
            u1.AddParameter("MS_REF","CRM_COM");
            u1.AddParameter("MS_REF_ID", key);
            u1.AddParameter("XMLNAME", "/business/crm/mail_send.xml");
            u1.AddParameter("ITEMNAME", "MAIL_SEND.LF.M");
        }  else {
            if(!sup_id || sup_id=="0"){
                $Tip("未签约客户");
                return;
            }

            if (cur_target_id == "QUERIES") { // 询价单
                u1.AddParameter("XMLNAME", "@xmlname");
                // u1.AddParameter("ITEMNAME", "index-sub-ENQ_MAIN.LF.M");
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("GRP_OR_ENQ","ENQ");
                u1.AddParameter("ITEMNAME", "index-GRP_MAIN.Lf.M");
            } else if (cur_target_id == "CPS") { // 预订单
                u1.AddParameter("XMLNAME", "/business/group/cp.xml");
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("ITEMNAME", "GRP_MAIN.LF.CP");
            } else if (cur_target_id == "GRP_NUM") { // 团列表
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("GRP_OR_ENQ","GRP");
                u1.AddParameter("XMLNAME", "@XMLNAME");
                u1.AddParameter("ITEMNAME", "index-GRP_MAIN.Lf.M");
            } else if (cur_target_id == "CLOSED_NUM") { // 团关闭
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("GRP_CLOSED","1");
                u1.AddParameter("XMLNAME", "@XMLNAME");
                u1.AddParameter("ITEMNAME", "index-GRP_MAIN.Lf.M");
            } else if (cur_target_id == "COS_NUM") { // 客人名单
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("FILTER","SALES");
                u1.AddParameter("XMLNAME", "/business/group/grp_customer.xml");
                u1.AddParameter("ITEMNAME", "GRP_COSTUMER.Lf.BookList");
            } else if (cur_target_id == "CONTRACTS") { // 客户协议
                u1.AddParameter("BY_SUP_ID", sup_id);
                u1.AddParameter("BY_FILE_TYPE", "PACT1");
                u1.AddParameter("XMLNAME", "@xmlname");
                u1.AddParameter("ITEMNAME", "index-CURRENCY_FILE.LF.V");
            } else if (cur_target_id == "PROM_NUM") { // 推广
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("XMLNAME", "///business/agent/study-tour.xml");
                u1.AddParameter("ITEMNAME", "GRP_MAIN.LF.preEnroll");
            }
        }

        let cnt_td = newTr.cells[0];
        $(cnt_td).addClass('add-pre-row');

        $(target_obj).addClass("customer-add-row-cur-td");
        let ajax_url = u1.GetUrl();
        $Install(ajax_url, cnt_td.id, function() {
            // console.log('install ok');
        });
    });
    ewa.AddPreRowCheck = function(tr, key, evt) {
        return true;

        let target = evt.target;
        let objId;
        for (let i = 0; i < this.valid_targets.length; i++) {
            let id = this.valid_targets[i];
            if ($(target).hasClass("ewa-col-" + id) || target.id == id) {
                objId=id;
                break;
            }
        }
        if(objId){
            return true;
        }
    };
    ewa.AddPreRowCloseEvent = function(frameUnid, tr, key, newTr, evt) {
        $("#EWA_LF_@sys_frame_unid>tbody>tr>td.customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
    };

    ewa.ReloadAfter = function() {
        //添加下一行事件元素添加样式
        for (let i = 0; i < this.valid_targets.length; i++) {
            $("#EWA_LF_" + this.Id + ">tbody>tr.ewa-lf-data-row>td.ewa-col-" + this.valid_targets[i])
                .addClass("customer-add-row-td");
        }
        //绑定按钮事件
        //打开客户面板
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butPanel]").on("click", function() {
            let name = $(this).attr("data-crm-com-name");
            let id = $(this).attr("data-crm-com-id");
            let u = "@EWA.CP/business/sales/agent-index.jsp?T=10&crm_com_id=" + id;
            if (top != window && top.AddTab) {
                top.AddTab(u, name);
            } else {
                window.open(u);
            }
        });
        //查看修改客户信息
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butModify]").on("click", function() {
            let id = $(this).attr("data-crm-com-id");
            let itemname="CRM_COM_NEW.Frame.Modify";
            let u1=ewa.getUrlClass();
            let paras="EWA_MTYPE=M&EWA_REDRAW=1&METHOD=DJ&CRM_COM_ID=" + id;
            if(u1.GetParameter("AUS_TYPE")){
                itemname="CRM_COM_NEW.Frame.New_easy";
                paras="EWA_MTYPE=M&CRM_COM_ID=" + id;
            }
            EWA.UI.Dialog.OpenReloadClose("@SYS_FRAME_UNID",
                "|business|crm|sales_crm.xml", itemname,
                false,
                paras);
        });
        //添加查看链接文字内容
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-col-linkView a").html(ewa.Resources.lkView.GetInfo());

        //添加联系记录
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butAddContact]").on("click", function() {
            let id = $(this).attr("data-crm-com-id");
            let p = 'EWA_MTYPE=N&CRM_COM_ID=' + id + "&COM_ID=" + id;
            EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
                '|business|crm|sales_crm.xml', 'CRM_RECORD.Frame.NewModify', false, p);
        });
        let u = new EWA_UrlClass(ewa.Url);
        if( "0" == u.GetParameter("CF_NEED")){ //全部客户
            $('#EWA_RESHOW_@SYS_FRAME_UNID .ewa-lf-menu').removeClass('ewa-lf-menu-marked');
            $('#EWA_RESHOW_@SYS_FRAME_UNID .ewa-lf-menu:eq(1)').addClass('ewa-lf-menu-marked')
        }


        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-NEW_CUSTOMER span[title='New']").attr("title","请填写联系记录或客户反馈");

        ewa.stickyColumns(4);
    }
    ewa.ReloadAfter();
})();

