Set.Sql:
select top 1 b.SUP_NAME+'是服务商(SP)，不能再添加为供应商(SA)' EWA_ERR_OUT from sup_sub a inner join sup_main b on a.SUP_DOWN_ID = b.sup_id where a.OWN_SUP_ID=@g_sup_id and a.SUP_DOWN_ID in (@IDS_SPLIT) ;
insert into sup_ser_conn(SUP_ID, SER_ID, SUP_UP_ID,SSC_STATUS,SSC_CDATE,SSC_ADM_ID) select a.sup_id,s.ser_id,b.sup_up_id,'USED',@sys_date,@g_adm_id from sup_main a inner join crm_conn b on a.sup_id=b.sup_down_id and b.sup_up_id=@g_sup_id, ser_main s where a.sup_id in (@IDS_SPLIT) and not exists(select 1 from sup_ser_conn x where a.sup_id=x.sup_id and x.ser_id=s.ser_id and x.sup_up_id=b.sup_up_id) and s.sup_id=3 and s.ser_id!=1035 and s.ser_id in (@ser_ids_split);
UPDATE sup_ser_conn SET SSC_STATUS = 'USED', SSC_MDATE = @SYS_DATE, SSC_M_ADM_ID = @G_ADM_ID WHERE SUP_ID in (@IDS_SPLIT) AND sup_up_id = @G_SUP_ID AND SSC_STATUS = 'DEL' AND ser_id IN (@ser_ids_split);
-- ewa_test @add_both is not null insert into sup_sub(SUP_UP_ID, SUP_DOWN_ID, SER_ID, SS_TAG, SS_CDATE, ADM_ID, OWN_SUP_ID) select a.sup_id,a.sup_id,s.ser_id,'服务商',getdate(),@g_adm_id, @g_sup_id from sup_main a inner join crm_conn b on a.sup_id=b.sup_down_id and b.sup_up_id=@g_sup_id , ser_main s where a.sup_id in (@IDS_SPLIT) and s.ser_id in (@ser_ids_split) and not exists(select 1 from sup_sub x where a.sup_id=x.sup_down_id and a.sup_id=x.sup_up_id and x.ser_id=s.ser_id and x.OWN_SUP_ID=@g_sup_id) -- ewa_test ; -- ewa_test @add_both is not null -- 添加到全部服务商列表 insert into sup_sub(SUP_UP_ID, SUP_DOWN_ID, SER_ID, SS_TAG, SS_CDATE, ADM_ID, OWN_SUP_ID) select -1 ,a.sup_id,s.ser_id,'服务商',getdate(),@g_adm_id, @g_sup_id from sup_main a inner join crm_conn b on a.sup_id=b.sup_down_id and b.sup_up_id=@g_sup_id , ser_main s where a.sup_id in (@IDS_SPLIT) and s.ser_id in (@ser_ids_split) and not exists(select 1 from sup_sub x where a.sup_id=x.sup_down_id and x.sup_up_id=-1 and x.ser_id=s.ser_id and x.OWN_SUP_ID=@g_sup_id) -- ewa_test ;

Set.Bottom:
(function() {
    var names = JSON.parse("@EWA.FRAME.DATA.ser_tag");
    console.log(names)

    var ewa = EWA.F.FOS["@sys_frame_unid"];
    ewa.valid_targets = ["CONTACTS"];

    function getObj(exp) {
        return exp ? $('#EWA_LF_@SYS_FRAME_UNID').find(exp) : $('#EWA_LF_@SYS_FRAME_UNID');
    }

    ewa.ext_addSerConn = function() {
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.RemoveEwa();
        u1.AddParameter("EWA_MTYPE", "N");
        u1.AddParameter("SER_ID", "@SER_ID");
        u1.AddParameter("EWA_IN_DIALOG", "1");
        if ("@sup_up_id") {
            u1.AddParameter("sup_id", "@sup_up_id");
        }
        u1.RemoveParameter("SER_ID");
        let ITEMNAME = '2025_SER_SET_SIG_SUP.F.NM';
        // if ('@ser_id' == '1') { // 机票
        //         ITEMNAME = "2025_SER_SET_SIG_SUP.F.SER_TAG_AIR";
        // }
        let p = u1.GetParas();
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '/business/crm/sup_ser.xml', ITEMNAME, false, p);
    }

    ewa.AddPreRowCheck = function(tr, key, evt) {
        if (!"@SER_ID") {
            //return false;
        }
        return "@NOT_EXPAND" ? false : true;
    };
    ewa.switchTab = function(obj) {
        getObj('.grp-part-tab-tag').removeClass('grp-part-tab-tag-selected');
        $(obj).addClass('grp-part-tab-tag-selected');
        getObj('.content').hide();
        getObj('[id="' + $(obj).attr('tag-for') + '"]').show();
    };

    function countLeadingSlashes(str) {
        const ss = [];
        for (let i = 0; i < str.length; i++) {
            if (str[i] === '/') {
                ss.push('|');
            } else {
                break; // 遇到非 '/' 就停止
            }
        }
        return ss.join('');
    }

    function showSerMains(cntTd, key, serMains) {
        $(cntTd).addClass('grp-part-tabs show-children');
        const id = cntTd.id;
        const tabs = [`<div class="grp-part-tab-tags">`];
        const contents = [``];
        const urls = [];
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.AddParameter('sup_up_id', key);
        u1.AddParameter("show_mode", "providers");
        // u1.AddParameter("ewa_title", "服务商(Service Provider)列表");
        u1.AddParameter("XMLNAME", "@XMLNAME");
        u1.AddParameter("ITEMNAME", "2025-index-sup_main.l.Provider");

        for (let i = 0; i < serMains.length; i++) {
            let d = serMains[i]; //数据行
            const tab = `<div class="grp-part-tab-tag  ${i==0?"grp-part-tab-tag-first":""}"
                        tag-for="${id}_${i}"
                        onclick='EWA.F.FOS["@sys_frame_unid"].switchTab(this)'>${d.SER_NAME.replace("服务","")}</div>`;
            tabs.push(tab);
            const content = `<div id="${id}_${i}" class='content' style='display:none'></div>`;
            contents.push(content);

            u1.AddParameter("EWA_FRAME_UNID_PREFIX", key + "_" + d.SER_ID);
            u1.AddParameter("SER_ID", d.SER_ID);

            let url = u1.GetUrl();
            urls.push(url);
        }
        tabs.push("</div>");
        $(cntTd).html(tabs.join('') + contents.join(''));
        for (let i = 0; i < urls.length; i++) {
            $Install(urls[i], `${id}_${i}`, function() {
                const total = $(`#${id}_${i}`).find('.ewa-total-records').text();
                console.log('total=' + total);
                if (total) {
                    $(`.grp-part-tab-tag[tag-for="${id}_${i}"]`).append('(' + total + ')')
                }
            });
        }
        $('div[tag-for=' + id + '_0]').trigger('click')
    }
    ewa.AddPreRow(function(frameUnid, tr, key, newTr, evt) {
        console.log(ewa.Id);
        var cntTd = newTr.cells[0];
        let u1 = new EWA_UrlClass(this.Url);
        u1.RemoveEwa();
        u1.AddParameter("XMLNAME","@XMLNAME");
        u1.AddParameter("ITEMNAME","@ITEMNAME");
        //获取供应商的服务列表
        u1.AddParameter("ewa_action", "ExtendAction2");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("sup_id", key);

        let u = u1.GetUrl();
        $J(u, function(rst) {
            showSerMains(cntTd, key, rst);
        });
        return;

    });

    ewa.ReloadAfter = function() {
        //添加下一行事件元素添加样式
        for (var i = 0; i < this.valid_targets.length; i++) {
            $("#EWA_LF_" + this.Id + " .ewa-lf-data-row .ewa-col-" + this.valid_targets[i]).addClass("customer-add-row-td");
        }
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butPanel]").on("click", function() {
            var sup_id = $(this).attr("data-sup-id");
            var crm_com_id = $(this).attr("data-crm-com-id");
            var u1 = "@ewa.cp/business/supply/supply-index.jsp?TP=2&CRM_COM_ID=" + crm_com_id + "&SUP_ID=" + sup_id + "&REF_ID=" + sup_id;
            if (top.AddTab && top != window) {
                top.AddTab(u1);
            } else {
                window.open(u1);
            }
        });
        //查看修改客户信息
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butModify]").on("click", function() {
            var sup_id = $(this).attr("data-sup-id");
            var crm_com_id = $(this).attr("data-crm-com-id");
            var paras = "EWA_MTYPE=M&EWA_REDRAW=1&SUP_ID=" + sup_id + "&CRM_COM_ID=" + crm_com_id;
            EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
                '/business/crm/supplier.xml', 'CRM_COM_SUP.EASY.F.M', false, paras);
        });
        //添加查看链接文字内容
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-col-linkView a").html(ewa.Resources.lkView.GetInfo());

        //添加联系记录
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butContact]").on("click", function() {
            var crm_com_id = $(this).attr("data-crm-com-id");
            var p = 'EWA_MTYPE=N&CRM_COM_ID=' + crm_com_id + "&COM_ID=" + crm_com_id;
            EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
                '|business|crm|sales_crm.xml', 'CRM_RECORD.Frame.NewModify', false, p);
        });
    }
    ewa.ReloadAfter();

    ewa.ext_convert = function() {
        //let paras = 'EWA_MTYPE=M&crm_com_id=' + crm_com_id + '&SUP_ID=' + sup_id;
        //console.log(paras)
        let paras = 'EWA_MTYPE=M';
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '/business/crm/supplier.xml', 'CRM_2_SUP.F.M', false, paras);
    }
    ewa.ext_addNewSup = function() {
        let paras = 'EWA_MTYPE=N&EWA_REDRAW=1&issup=1';
        let u1 = ewa.getUrlClass();
        let serId = u1.GetParameter("SER_ID");
        if (serId) {
            paras += "&SER_ID="+serId;
        }
        let supUpId = u1.GetParameter("SUP_UP_ID");
        if (supUpId) {
            paras += "&SUP_UP_ID=" + supUpId;
        }
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
            '|business|crm|supplier.xml', 'CRM_COM_SUP.F.NM', false, paras);
    }
})();

Set.Sql:
WITH supplies AS ( -- 供应商列表（新版） SELECT distinct sup_id SUP_DOWN_ID, cc.CRM_CONN_CREATE_TIME, cc.CRM_COM_ID, cc.CRM_CONN_ID, cc.CRM_CONN_TAG, cc.adm_id, case when cc.SUP_DOWN_ID = cc.sup_UP_id then 0 else 1 end SUP_ORD FROM sup_ser_conn a INNER JOIN CRM_CONN CC ON CC.SUP_DOWN_ID = a.SUP_ID AND CC.sup_UP_id = @g_sup_id AND a.sup_UP_id = @g_sup_id AND a.ssc_status = 'USED' ), w_sers AS ( SELECT sc.SUP_ID, count(1) services FROM SER_CONN sc WHERE sc.OWN_SUP_ID = @g_sup_id AND ser_conn_state = 'USED' AND SER_CONN_VER = '2026' -- ewa_test @ser_id > 0 AND sc.ser_id = @ser_id -- ewa_test GROUP by sc.SUP_ID ), w_sup_ser_types as ( select SUP_DOWN_ID, stuff((select ','+sm.SER_TAG from sup_ser_conn x inner join ser_main sm on x.ser_id=sm.ser_id and sm.sup_id=3 where a.SUP_DOWN_ID=x.SUP_ID and x.SUP_UP_ID=@g_sup_id and x.ssc_status = 'USED' group by sm.SER_TAG for xml path('') ),1,1,'') SUP_SER_TYPES from supplies a ), BILL AS ( --收付款，团状态为客户确认 SELECT B.RELATE_SUP_ID, sum(PAY_PLAN) AS PAY_PLAN, sum(PAY_REAL) AS PAY_REAL, sum(PAY_UN) AS PAY_UN FROM GRP_MAIN A INNER JOIN GRP_PAY_BILL B ON A.GRP_ID = B.GRP_ID AND A.GRP_STA = 'SCM_GRP_STA_UNENQ' AND A.GRP_STATE = 'USED' AND (A.CLAC_STATUS != 'FINALLY_CLOSE') AND GRP_SDATE > getdate() - 365 -- 一年有效，超过一年默认关闭 AND A.GRP_PID IS NULL AND A.SUP_ID = @G_SUP_ID INNER JOIN supplies ON b.RELATE_SUP_ID = supplies.SUP_DOWN_ID GROUP BY B.RELATE_SUP_ID ), GRPS_PROGRESS AS ( SELECT RELATE_SUP_ID, count(*) AS GRPS_PROGRESS FROM ( SELECT DISTINCT B.RELATE_SUP_ID, b.GRP_ID FROM GRP_MAIN A INNER JOIN GRP_PAY_BILL B ON A.GRP_ID = B.GRP_ID AND A.GRP_STA = 'SCM_GRP_STA_UNENQ' AND A.GRP_STATE = 'USED' AND (A.CLAC_STATUS != 'FINALLY_CLOSE') AND GRP_SDATE > getdate() AND A.GRP_PID IS NULL AND A.SUP_ID = @G_SUP_ID INNER JOIN supplies ON b.RELATE_SUP_ID = supplies.SUP_DOWN_ID ) AA GROUP BY RELATE_SUP_ID ), HIS_BILL AS ( --历史营业额 SELECT B.RELATE_SUP_ID, sum(PAY_REAL) AS HIS_PAY_REAL FROM GRP_MAIN A INNER JOIN GRP_PAY_BILL B ON A.GRP_ID = B.GRP_ID -- 一年有效，超过一年默认关闭 AND ( A.CLAC_STATUS = 'FINALLY_CLOSE' OR GRP_SDATE <= getdate() - 365 ) AND A.SUP_ID = @G_SUP_ID INNER JOIN supplies ON b.RELATE_SUP_ID = supplies.SUP_DOWN_ID GROUP BY B.RELATE_SUP_ID ), GRPS_HIS AS ( --已关闭团 SELECT RELATE_SUP_ID, count(*) AS GRPS_HIS FROM ( SELECT DISTINCT B.RELATE_SUP_ID, b.GRP_ID FROM GRP_MAIN A INNER JOIN GRP_PAY_BILL B ON A.GRP_ID = B.GRP_ID AND (A.CLAC_STATUS = 'FINALLY_CLOSE') AND A.GRP_PID IS NULL AND A.SUP_ID = @G_SUP_ID INNER JOIN supplies ON b.RELATE_SUP_ID = supplies.SUP_DOWN_ID ) AA GROUP BY RELATE_SUP_ID ), QUERIES AS ( --询价单数量，在使用的询价 SELECT COUNT(1) SUP_QUERIES, SUP_ID, max(CREATE_TIME) AS LAST_OP FROM ENQ_OP_MAIN b INNER JOIN supplies ON b.SUP_ID = supplies.SUP_DOWN_ID WHERE ENQ_OP_STATE = 'USED' AND OWN_SUP_ID = @G_SUP_ID GROUP BY SUP_ID ), QUOTES AS ( --报价单数量，状态是结束 SELECT COUNT(1) SUP_QUOTES, SUP_ID FROM ENQ_OP_MAIN b INNER JOIN supplies ON b.SUP_ID = supplies.SUP_DOWN_ID WHERE ENQ_OP_STATE = 'USED' AND STATE = 'ENQ_FIN' AND OWN_SUP_ID = @G_SUP_ID GROUP BY SUP_ID ), CONTRACTS AS ( -- 报价合同数量，状态是结束且有合同文件 SELECT COUNT(1) SUP_CONTRACTS, SUP_ID FROM ENQ_OP_MAIN b INNER JOIN supplies on b.SUP_ID = supplies.SUP_DOWN_ID WHERE ENQ_OP_STATE = 'USED' AND STATE = 'ENQ_FIN' AND PIC_PHY_PATH IS NOT NULL AND OWN_SUP_ID = @G_SUP_ID GROUP BY SUP_ID ), ser AS ( SELECT DISTINCT SUP_ID FROM ser_conn a INNER JOIN supplies on a.SUP_ID = supplies.SUP_DOWN_ID WHERE a.ser_key0 = @ser_key_id OR a.ser_key1 = @ser_key_id ) SELECT * FROM ( SELECT sm.*, au.adm_name, S.CITY_NAME, smt.bas_TAG_NAME AS SUP_MTAG_NAME, supplies.CRM_COM_ID, supplies.CRM_CONN_ID, supplies.CRM_CONN_CREATE_TIME, BILL.*, GRPS_PROGRESS.GRPS_PROGRESS, HIS_BILL.HIS_PAY_REAL, GRPS_HIS.GRPS_HIS, QUERIES.SUP_QUERIES, QUERIES.LAST_OP, -- 最后下单时间 QUOTES.SUP_QUOTES, country.CITY_NAME COUNTRY_NAME, sers.services, st.SUP_SER_TYPES, supplies.SUP_ORD FROM SUP_MAIN sm INNER JOIN supplies ON sm.SUP_ID = supplies.SUP_DOWN_ID LEFT JOIN w_sers sers ON sm.SUP_ID = sers.SUP_ID LEFT JOIN CITY S ON SM.CITY_ID1 = S.CITY_ID LEFT JOIN city country ON s.COUNTRY_ID = country.CITY_ID LEFT JOIN bas_tag smt ON smt.bas_TAG = supplies.CRM_CONN_TAG LEFT JOIN adm_user au ON au.adm_id = supplies.adm_id LEFT JOIN BAS_TAG bt2 ON sm.SIGN_TAG = bt2.BAS_TAG LEFT JOIN SUP_INBOUND inbound ON sm.sup_id = inbound.sup_id left join w_sup_ser_types st on sm.sup_id=st.SUP_DOWN_ID -- 收付款，团状态为客户确认 LEFT JOIN BILL ON SM.sup_id = BILL.RELATE_SUP_ID -- 新团数量，团状态为客户确认 LEFT JOIN GRPS_PROGRESS ON SM.sup_id = GRPS_PROGRESS.RELATE_SUP_ID -- 历史营业额 LEFT JOIN HIS_BILL ON SM.sup_id = HIS_BILL.RELATE_SUP_ID -- 已关闭团 LEFT JOIN GRPS_HIS ON SM.sup_id = GRPS_HIS.RELATE_SUP_ID -- 询价单数量，在使用的询价 LEFT JOIN QUERIES ON sm.sup_id = QUERIES.SUP_ID -- 报价单数量，状态是结束 LEFT JOIN QUOTES ON sm.sup_id = QUOTES.SUP_ID -- 报价合同数量，状态是结束且有合同文件 LEFT JOIN CONTRACTS ON sm.sup_id = CONTRACTS.SUP_ID -- ewa_test @ser_key_id > 0 LEFT JOIN ser ON sm.sup_id = ser.SUP_ID -- ewa_test WHERE 1 = 1 -- ewa_test @IN_GRP_CARD is NOT NULL AND sm.sup_id IN (@SUP_ID_SPLIT) -- ewa_test @ser_id > 0 and @sup_UP_id is null AND sers.sup_id > 0 -- ewa_test @ser_key_id > 0 AND (ser.SUP_ID > 0) -- ewa_test @show_tag = 'inbound' AND ( @show_tag = 'inbound' AND inbound.SUP_ID > 0 ) -- ewa_test @ASSOCIATED_SUPPLIERS is not null -- 相关的供应商，用于供应商管理面板中 AND ( sm.SUP_ID=@SUP_ID or sm.SUP_ID in (select SUP_UP_ID from sup_sub where SUP_DOWN_ID=@SUP_ID AND OWN_SUP_ID=@G_SUP_ID) ) -- ewa_test @SIGN_TAG is not null and SIGN_TAG = @SIGN_TAG -- ewa_test ) sl WHERE 1 = 1 ORDER BY SUP_ORD, SUP_ID DESC;
-- ewa_table_name ser_main SELECT A.SER_ID, A.SER_NAME, A.SER_NAME_EN FROM ser_main a inner JOIN sup_ser_conn b on a.ser_id = b.ser_id and b.ssc_status = 'USED' WHERE A.ser_ob3 = 'USED' AND A.ser_id != 1035 ORDER BY SER_ORD;
-- ewa_table_name ser_tag SELECT SER_TAG, SER_TAG_ID, SER_TAG_NAME, SER_TAG_NAME_EN FROM ser_tag WHERE ser_id = @ser_id AND ser_tag_status = 'USED' AND ser_tag LIKE 'TAG0' ORDER BY ser_tag_ord;

SELECT '北京路嘉阳光国际旅行社有限公司，不能移除' AS ewa_err_out WHERE 3 = @sup_id;
SELECT '不能移除自己' AS ewa_err_out WHERE @g_sup_id = @sup_id;
SELECT '已经有服务了，不能移除' AS ewa_err_out WHERE EXISTS ( SELECT 1 FROM ser_conn WHERE sup_id = @sup_id AND ser_conn_state = 'USED' and ser_conn_ver = '2026' );
DELETE FROM sup_ser_conn WHERE sup_id = @sup_id AND sup_up_id = @g_sup_id AND sup_id NOT IN (3, @g_sup_id) AND NOT EXISTS ( SELECT 1 FROM ser_conn WHERE sup_id = @sup_id AND ser_conn_state = 'USED' and ser_conn_ver = '2026' )

