function showCloseApply(grp_id) {
    if (grp_id !== 0) {
        window.parent.frames[1].location = '@ewa.cp/ewa?XMLNAME=business|group|workflowbiz.xml&ITEMNAME=GRP_CLOSE_APPLY.close.ListFrame.Modify&grp_id=' + grp_id;

    } else {
        alert('请签约该客户');
        return fasle;
    }
}

