                    pub+="<b style='color: green' class='fa fa-check' title='已发布到网站'></b>";
                }
            }
            $(this).find("#GRP_GYAP_PUB").html(pub);
        });

        getObj("tr.ewa-lf-data-row .ewa-col-PD_NAME a[title]").each(function() {
            $(this).html("海报");
        });

    }
