    // 报名二维码
    ewa.ext_EnrollQrcode = function(obj) {
        let tr = $(obj).closest("tr");
        let grpUnid = tr.attr("data-grp-unid");
        let grpHyCode = tr.find("#GRP_HY_CODE").text().trim();
        let grpName = tr.find("#GRP_NAME").text().trim();
        let supDownId = tr.attr("data-sup-down-id");
        let domain = location.host.indexOf('gdx') >= 0 ? "gdx8" : "www.gyap.org";
        let grpId = tr.attr("data-grp-id");
        let connId = tr.attr("data-conn-id");

        let targetUrl = "https://" + domain + "/" + (EWA.CP.split("/")[1]) +
            "/customer/study-tour/enrollframe.jsp?grp_unid=" + grpUnid;

        let tip = grpName + '<br>' + grpHyCode;
        let u3 = new EWA_UrlClass("/");
        u3.AddParameter("target_url", targetUrl);
        u3.AddParameter("convert_short_url", 1);
        u3.AddParameter("tip", tip);
        u3.AddParameter("img_name", grpHyCode);
        u3.AddParameter("show_adm_unid", 1);
        u3.AddParameter("I_Am_Recommender", 1);
        u3.AddParameter("recommender", 1);
        u3.AddParameter("SUP_DOWN_ID", supDownId);
        if (connId) {
            u3.AddParameter("REF_TABLE", "GRP_MAIN.ENROLL");
            u3.AddParameter("REF_ID", grpId);
            u3.AddParameter("CONN_ID", connId);
        }

        let paras = u3.GetParas();
        EWA.UI.Dialog.OpenFrame("create_qrcode", "/business/common/tools.xml", "QRCODE.F.N", false, paras);
    }
    if ('@ref_grp_id') {
