    ewa.ext_poster = function(connId, grpId) {
        let paras = "REF_TABLE=GRP_MAIN.ENROLL&PD_TAG=STUDY_TOUR&ewa_in_dialog=1&EWA_HEIGHT=400";
        paras += "&REF_ID=" + grpId;
        if (connId) {
            let domain = location.host.indexOf('gdx') >= 0 ? "gdx8" : "www.gyap.org";
            let url = "@ewa.cp/business/cs/application-poster-conn.jsp?REF_TABLE=GRP_MAIN.ENROLL&REF_ID=" + grpId + "&CONN_ID=" + connId;
            window.open(url);
            return;
        } else {
            paras += "&EWA_MTYPE=N";
        }
        if (!"@VIEW_ACL" || "@T" == "10") {
            paras += "&T=10";
        }
        EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid", "/business/poster-design/pd-list.xml", "PD_CONN.F.NM", false, paras);
    }

    function init() {
        if ("@view_tag" != 'QG') { //非报价团，移除回收站 
            $("div.ewa-lf-func-recycle[onclick='EWA.F.FOS[\"@sys_frame_unid\"].ShowRecycle1(this)']").remove();
            return;
        }
        // 报价团回收站改名为过期报价
        let pastGrp = "<b class='fa fa-calendar'>过期报价</b>";
        $("div.ewa-lf-func-recycle[onclick='EWA.F.FOS[\"@sys_frame_unid\"].ShowRecycle1(this)']").html(pastGrp);
    }
    init();
});

(function() {
    // 备份一下

    function getGrpId() {
        var ids = EWA.F.FOS["@SYS_FRAME_UNID"].SelectChecked();
        if (ids == '') {
            alert('请先选择一个团');
        }
        return ids;
    }
    // 团支出项
    function btnPayType() {
        var grpId = getGrpId();
        if (grpId == '')
            return;

        var urlx = '@ewa.cp/ewa?xmlname=business/group/op.xml&itemname=GRP_FIN_TYPE.PayListFrame.Modify&GRP_ID=' + grpId;
        window.parent.frames[1].location = urlx;
    }
    // 团收款项
    function btnIncomeType() {
        var grpId = getGrpId();
        if (grpId == '')
            return;

