        if (grpId == '')
            return;
        var urlx = '@ewa.cp/ewa?xmlname=/business/group/op.xml&itemname=GRP_FIN_TYPE.incomeListFrame.Modify&GRP_ID=' + grpId;
        window.parent.frames[1].location = urlx;
    }
    // 团收款功能
    function butIncomeForm() {
        var grpId = getGrpId();
        if (grpId == '')
            return;
        var urlx = '@ewa.cp/ewa?xmlname=/business/group/op.xml&itemname=V_GRP_FIN_VIEW.incomeListFrame.Modify&GRP_ID=' + grpId;
        window.parent.frames[1].location = urlx;
    }
    // 团操作日志
    function showOpLog() {
        var grpId = getGrpId();
        if (grpId == '')
            return;
        var urlx = '@ewa.cp/ewa?xmlname=/business/group/op.xml&itemname=OP_LOG.ListFrame.View&GRP_ID=' + grpId;
        window.parent.frames[1].location = urlx;
    }

    function showPayApply() {
        var grpId = getGrpId();
        if (grpId == '')
            return;
        var urlx = '@ewa.cp/ewa?xmlname=/business/group/op.xml&itemname=GRP_PAY_APPLY.ListFrame.Modify&GRP_ID=' + grpId;
        window.parent.frames[1].location = urlx;
    }

    function sp(t) {
        var u = '@ewa.cp/ewa?XMLNAME=business/common/droplist.xml&ITEMNAME=SYS_STATUS.Frame.New';
        var p = 'sys_sta_rid=@grp_id&sys_sta_table=GRP_MAIN';
        if (t == 90) {
            p += '&sys_sta_tag=SCM_GRP_STA_ENQUIRY'
        }
        EWA.UI.Dialog.OpenReloadClose('@sys_frame_unid', 'business/common/droplist.xml',
            'SYS_STATUS.Frame.New', false, p);
    }

    function getHtml() {
        var ajax = new EWA_AjaxClass();
        ajax.AddParameter("grp_id", '@grp_id');
        ajax.AddParameter("enq_ID", '@enq_id');
        ajax.PostNew('@ewa.cp/ewa?XMLNAME=business/enq/price.xml&ITEMNAME=ENQ_LIST', function() {
            if (!ajax.IsRunEnd()) {
                return;
            }
            html = ajax.GetRst();
        });
    }

    function reOpen(grpId, enqId) {
        if (enqId == null || enqId == '') {
            alert('该团还未提交，无需重新开放！');
            return;
        }
        var html;
        var paras = [];
        paras[0] = {
            Name: 'grp_id',
            Value: grpId
        };
        paras[1] = {
            Name: 'enq_id',
            Value: enqId
        };
        var ajax = new EWA_AjaxClass();
        ajax.AddParameter("grp_id", "@grp_id");
        ajax.AddParameter("enq_ID", enqId);
        ajax.PostNew('@ewa.cp/ewa?XMLNAME=business/enq/price.xml&ITEMNAME=ENQ_LIST', function() {
            if (!ajax.IsRunEnd()) {
                return;
            }
            html = ajax.GetRst();
            paras[2] = {
                Name: 'html',
                Value: html
            };

            EWA.F.FOS['@SYS_FRAME_UNID'].DoAction(this, 'ExtendActionx', '你确认要重新开放么', '', paras);
        });
    }

    function reopen1(grpId, enqId, grpopenid) {
        if (enqId == null || enqId == '') {
            alert('该团还未提交，无需重新开放！');
            return;
        }
        var p = '&EWA_MTYPE=N&GRP_ID=' + grpId + '&ENQ_ID=' + enqId + '&grp_open_id=' + grpopenid;
        EWA.UI.Dialog.OpenReloadClose('@sys_frame_unid', 'business/group/journey.xml',
            'GRP_OPEN.Frame.NewModify', false, p);
    }

    function reopenfin(grpId, enqId, grpopenid) {
        if (enqId == null || enqId == '') {
            alert('该团还未提交，无需重新开放！');
            return;
        }
        var p = '&EWA_MTYPE=M&GRP_ID=' + grpId + '&ENQ_ID=' + enqId + '&grp_open_id=' + grpopenid;
        EWA.UI.Dialog.OpenReloadClose('@sys_frame_unid', 'business/group/journey.xml',
            'GRP_OPEN.Frame.NewModify', false, p);
    }

    function gyap_batch_copy() {
        EWA.UI.Dialog.OpenReloadClose('@sys_frame_unid', '/business/gyap-project/design.xml',
            'GRP_GYAP_DOC_COPY_BATCH', false, null);
    }
})();

