Set.Sql:
-- EWA_SQL_SPLIT_NO SELECT TOP 1 BAS_TAG CURRENT_YEAR FROM BAS_TAG WHERE BAS_TAG_GRP='YEARS' AND BAS_TAG_PARA1='CURRENT' ORDER BY BAS_TAG DESC ;
with w_CONTACTS as ( SELECT B.CRM_COM_ID AS ID1, COUNT(*) AS CONTACTS FROM CRM_RECORD A INNER JOIN CRM_CUS B ON A.CRM_CUS_ID = B.CRM_CUS_ID WHERE A.SUP_ID=@G_SUP_ID GROUP BY B.CRM_COM_ID ), w_last_feedback as ( select CRM_COM_ID,max(CF_MDATE) LAST_CF_MDATE from CRM_FEEDBACK where CF_HIS='N' group by CRM_COM_ID ), w_outbox as ( select count(1) SENT_NUM,MS_REF_ID from MAIL_SEND where ms_ref='CRM_COM' and MS_STATUS='USED' group by MS_REF_ID ) -- ewa_test @AUS_TYPE is null , w_grp_types as ( select bas_tag from bas_tag where BAS_TAG_GRP='GRP_TYPE' and BAS_TAG_PARA2='USED' and not BAS_TAG in ('GRP_CB', 'GRP_VIRTUAL', 'GRP_ZC') ), w_QUERIES as( -- 询价单 SELECT A.SUP_DOWN_ID ID_QUERIES, COUNT(*) QUERIES FROM GRP_MAIN A WHERE GRP_STA='SCM_GRP_STA_NEW' AND A.GRP_STATE = 'USED' AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND A.GRP_SDATE>@SYS_DATE AND A.GRP_TYPE in (select BAS_TAG from w_grp_types) GROUP BY A.SUP_DOWN_ID ), w_CPS as ( -- 预订团 SELECT A.SUP_DOWN_ID ID_CP, COUNT(*) CPS FROM GRP_MAIN A WHERE A.GRP_STATE = 'USED' AND A.CP_STATUS = 'COM_YES' AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND A.GRP_SDATE >= dateadd(m,-1,@EWA.DATE.STR) AND A.GRP_TYPE in (select BAS_TAG from w_grp_types) GROUP BY A.SUP_DOWN_ID ), w_GRPS as ( -- 团列表 select count(1) GRP_NUM,a.SUP_ID ID_GRP from sup_main a inner join grp_main b on b.GRP_TYPE in (select BAS_TAG from w_grp_types) and ((a.sup_id=b.SUP_DOWN_ID and b.GRP_STA='SCM_GRP_STA_UNENQ') -- 包括散拼团 -- or exists(select 1 from GRP_COSTUMER gc -- where a.sup_id=gc.RELATE_SUP_ID and b.grp_id=gc.GRP_ID -- and gc.COS_STATUS = 'COS_NEW') ) where b.sup_id=@G_SUP_ID and b.GRP_STATE = 'USED' AND b.GRP_PID IS NULL group by a.SUP_ID ), w_cos as ( select COUNT(1) COS_NUM ,gc.RELATE_SUP_ID from GRP_COSTUMER gc inner join grp_main gm on gc.grp_id=gm.grp_id inner join w_grp_types w on gm.GRP_TYPE=w.BAS_TAG where 1=1 group by RELATE_SUP_ID ), w_closed as ( -- 团关闭 SELECT A.SUP_DOWN_ID ID_CLOSED, COUNT(*) CLOSED_NUM FROM GRP_MAIN A WHERE A.GRP_STATE = 'USED' AND A.CLAC_STATUS='FINALLY_CLOSE' AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND A.GRP_TYPE in (select BAS_TAG from w_grp_types) GROUP BY A.SUP_DOWN_ID ), w_CUST_PROGRESSES as ( SELECT B.RELATE_SUP_ID ID5 , SUM(B.BILL_RECEIVABLE) AS BILL_RECEIVABLE , SUM(B.BILL_RECEIVED) AS BILL_RECEIVED FROM GRP_MAIN A INNER JOIN GRP_BILL B ON A.GRP_ID = B.GRP_ID AND A.GRP_STATE = 'USED' AND A.GRP_PID IS NULL AND A.SUP_ID=@G_SUP_ID AND A.GRP_TYPE in (select BAS_TAG from w_grp_types) GROUP BY B.RELATE_SUP_ID ), w_ct as ( select COUNT(1) CONTRACTS,a.RELATE_SUP_ID from CURRENCY_FILE a inner join GRP_MAIN b on a.GRP_ID=b.GRP_ID where a.FILE_TYPE='PACT1' and b.GRP_STATE='USED' and PIC_PHY_PATH IS NOT NULL AND PIC_PHY_PATH != '' and STATE='USED' and a.SUP_ID=@G_SUP_ID AND b.GRP_TYPE in (select BAS_TAG from w_grp_types) group by a.RELATE_SUP_ID ), w_profit as ( select RELATE_SUP_ID ,(TOTAL_PRICE-TOTAL_COST) TOTAL_PROFIT -- 忽略自备签 -- ,(TOTAL_PRICE-IG_OWN_VISA_TOTAL_COST) IG_OWN_VISA_PROFIT from V_TOTAL_PRICE_BY_SUP a where a.sup_id=@G_SUP_ID ), w_promotions as ( select count(1) PROM_NUM ,SUP_DOWN_ID from grp_main where grp_type like 'GRP_TYPE_BMYX%' and GRP_STATE='USED' and sup_id=@G_SUP_ID group by SUP_DOWN_ID ), w_new_crm as ( select a.CRM_COM_ID,'New' NEW_CUSTOMER from crm_com a where aus_type='LEAD_WEBSITE' and USE_STATE='USED' and not exists(select 1 from CRM_FEEDBACK x where a.CRM_COM_ID=x.CRM_COM_ID) and not exists(select 1 from CRM_RECORD x inner join crm_cus y on x.CRM_CUS_ID = y.CRM_CUS_ID where a.CRM_COM_ID=y.CRM_COM_ID and x.ADM_ID=a.ADM_ID) ) -- ewa_test @IN_CAMP is not null , w_in_camp as ( select gc.RELATE_SUP_ID from CAMP_GRP_CONN cgc inner join GRP_COSTUMER gc on cgc.GRP_ID = gc.GRP_ID where cgc.STATE = 'USED' and gc.COS_STATUS = 'COS_NEW' group by gc.RELATE_SUP_ID ) -- ewa_test SELECT * FROM ( SELECT CASE WHEN cc.SUP_DOWN_ID IS NULL then 'CRM_COM_STAR_STATUS_A' else isnull(CRM_COM_STAR_STATUS,'CRM_COM_STAR_STATUS_B') end TAG , DEP_NAME , CRM_CONN_TAG , V.* , isnull(cc.sup_down_id,0) r_sup_id , CASE WHEN cc.SUP_DOWN_ID IS NULL THEN 'SIGN_NO' ELSE 'SIGN_YES' END SIGN , A0.ADM_NAME , CONTACTS.CONTACTS , case when cf.CF_ID is null then 'COM_NO' else 'COM_YES' end CF_NEED , cf.CF_YEAR , isnull(cf.CF_PROGRESS,0) CF_PROGRESS , LAST_CF_MDATE CF_MDATE , CC.ADM_ID SALE_ID , convert(date,V.CRM_COM_CDATE) FT_CRM_COM_CDATE , isnull(v.AUS_TAID,v.ADM_ID) CREATE_ADM_ID , c.CITY_NAME PROVINCE , w_outbox.SENT_NUM -- ewa_test @AUS_TYPE is null , QUERIES.QUERIES , w_CPS.CPS , CUST_PROGRESSES.* , BILL_RECEIVABLE - BILL_RECEIVED as BILL_UNPAY , ct.CONTRACTS , grps.GRP_NUM , w_closed.CLOSED_NUM , w_cos.COS_NUM -- , w_profit.TOTAL_PROFIT , w_promotions.PROM_NUM , w_new_crm.NEW_CUSTOMER -- ewa_test FROM CRM_COM V left join CRM_FEEDBACK cf on v.CRM_COM_ID=cf.CRM_COM_ID and cf.CF_HIS='N' and cf.CF_YEAR=@CURRENT_YEAR LEFT JOIN CRM_CONN CC ON V.CRM_COM_ID = CC.CRM_COM_ID AND CC.SUP_UP_ID = @G_SUP_ID LEFT JOIN BAS_TAG B1 ON B1.BAS_TAG = CRM_CONN_TAG LEFT JOIN ADM_USER A0 ON v.ADM_ID = A0.ADM_ID LEFT JOIN ADM_DEPT A1 ON A1.DEP_ID = A0.ADM_DEP_ID left join city c on v.province_id=c.city_id LEFT JOIN w_contacts CONTACTS ON V.CRM_COM_ID = CONTACTS.ID1 left join w_last_feedback last_cf on v.CRM_COM_ID=last_cf.CRM_COM_ID left join w_outbox on v.CRM_COM_ID=w_outbox.MS_REF_ID -- ewa_test @AUS_TYPE is null LEFT JOIN w_QUERIES QUERIES ON CC.SUP_DOWN_ID = QUERIES.ID_QUERIES -- 询价单 LEFT JOIN w_CPS ON w_CPS.ID_CP = CC.SUP_DOWN_ID -- 报价列表 LEFT JOIN w_CUST_PROGRESSES CUST_PROGRESSES ON CUST_PROGRESSES.ID5 = CC.SUP_DOWN_ID LEFT JOIN w_ct ct on cc.SUP_DOWN_ID=ct.RELATE_SUP_ID --团合同数量 left join w_grps grps on cc.SUP_DOWN_ID=grps.ID_GRP left join w_closed on cc.SUP_DOWN_ID=w_closed.ID_CLOSED left join w_cos on cc.SUP_DOWN_ID = w_cos.RELATE_SUP_ID left join w_profit on cc.SUP_DOWN_ID = w_profit.RELATE_SUP_ID left join w_promotions on CC.SUP_DOWN_ID=w_promotions.SUP_DOWN_ID left join w_new_crm on v.CRM_COM_ID=w_new_crm.CRM_COM_ID -- ewa_test @IN_CAMP is not null inner join w_in_camp on cc.SUP_DOWN_ID=w_in_camp.RELATE_SUP_ID -- ewa_test WHERE V.SUP_ID = @G_SUP_ID -- 2025-02-05 客户是客户，供应商是供应商（王总） and (cc.CRM_CONN_TAG is null or cc.CRM_CONN_TAG='SUP_TYPE_CUS' or cc.CRM_CONN_TAG= 'SUP_TYPE_ALL') and (cc.CRM_CONN_OB3 is null or cc.CRM_CONN_OB3!='FROM_SER_CONVERT') and (A0.ADM_ID IS NULL OR A0.SUP_ID=@G_SUP_ID) AND (v.CRM_COM_BUSINESS_TYPE is null or v.CRM_COM_BUSINESS_TYPE!='CC_BUSINESS_TYPE_SUP') -- 区分线索库里未签约的供应商 -- ewa_test isnull(@CF_NEED,'') = '1' and LAST_CF_MDATE is not null -- ewa_test @AUS_TYPE is null AND ( V.ADM_ID=@G_ADM_ID OR @VIEW_ACL = 'ALL' OR @VIEW_ACL = 'DEPT' AND A0.ADM_ID in (@G_SUB_IDS_SPLIT) ) and v.ADM_ID > 0 -- ewa_test @AUS_TYPE is not null and @AUS_TYPE!='' -- 自媒体客户 AND v.AUS_TYPE=@AUS_TYPE AND ((V.ADM_ID=@G_ADM_ID or V.AUS_TAID=@G_ADM_ID) -- 销售或自媒体客户填写人 or @VIEW_ACL = 'ALL' OR @VIEW_ACL = 'DEPT' AND (A0.ADM_ID in (@G_SUB_IDS_SPLIT) or v.AUS_TAID in (@G_SUB_IDS_SPLIT) ) ) -- ewa_test ) AS TE WHERE USE_STATE='USED' order by CRM_COM_ID DESC ;
-- ewa_table_name CRM_LEAD_TEMPLATE select min(CLT_ID) CLT_ID,CLT_TYPE,count(1) CLT_NUM from CRM_LEAD_TEMPLATE where CLT_STATUS='USED' and SUP_ID=@G_SUP_ID and CLT_CAT='SUP_TYPE_CUS' group by CLT_TYPE

select '已分配销售不能删除' EWA_ERR_OUT WHERE exists( select 1 from CRM_COM WHERE CRM_COM_ID = @CRM_COM_ID and ADM_ID is not null) or exists( select 1 from crm_conn where CRM_COM_ID=@CRM_COM_ID ) ;
select '只能删除自己或下属添加的客户' EWA_ERR_OUT where not exists (select 1 from CRM_COM where CRM_COM_ID = @CRM_COM_ID and (AUS_TAID = @G_ADM_ID or AUS_TAID in (@G_SUB_IDS_SPLIT))) ;
UPDATE CRM_COM SET USE_STATE='DEL' ,CRM_COM_MDATE=@SYS_DATE ,M_ADM_ID = @G_ADM_ID WHERE CRM_COM_ID = @CRM_COM_ID and (AUS_TAID = @G_ADM_ID or AUS_TAID in (@G_SUB_IDS_SPLIT)) and ADM_ID is null and not exists( select 1 from crm_conn where CRM_COM_ID=@CRM_COM_ID ) and sup_id=@g_sup_id

