EWA.F.FOS["@sys_frame_unid"].ext_newCrmCom = function(noLead) { //添加新客户let part=$("#EWA_LF_@SYS_FRAME_UNID").closest(".grp-part");
    let part = $("#EWA_LF_@SYS_FRAME_UNID").closest(".grp-part");
    if (part.length > 0) {
        let allTag = part.find(".grp-part-adds a[tag=0]");
        if (allTag.length > 0 && !allTag.hasClass("chked")) {
            allTag.click();
        }
    }
    let itemname = "CRM_COM_NEW.Frame.NewModify";
    let paras = "EWA_MTYPE=N";
    let u1 = this.getUrlClass();
    let ausType = u1.GetParameter("AUS_TYPE");
    if (ausType && !noLead) { // 客户线索库
        paras += "&AUS_TYPE=" + ausType;
        itemname = "CRM_COM_NEW.Frame.New_easy";
    }
    EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
        '/business/crm/sales_crm.xml', itemname, false, paras, "");
}

