async function agent_master_login_qrcode(supDownId, crmComId) {
    let ewa = EWA.F.FOS["@sys_frame_unid"];
    let u1 = ewa.getUrlClass();
    u1.RemoveEwa();
    u1.AddParameter("xmlname", "@xmlname");
    u1.AddParameter("ITEMNAME", "index-CRM_COM.Lf.M");
    u1.AddParameter("EWA_AJAX", "json_all");
    u1.AddParameter("EWA_ACTION", "getMasterContact");
    //获取代理和联系人信息
    let rstAll = await new Promise((resolve) => {
        if (supDownId) {
            u1.AddParameter("SUP_DOWN_ID", supDownId);
        }
        if (crmComId) {
            u1.AddParameter("CRM_COM_ID", crmComId);
        }
        $J(u1.GetUrl(), function(rst) {
            return resolve(rst);
        });
    });

    let com = rstAll[0];
    if (com.length == 0 || !com[0]["SUP_DOWN_ID"]) {
        $Tip("还未签约");
        return;
    }
    supDownId = com[0]["SUP_DOWN_ID"];
    crmComId = com[0]["CRM_COM_ID"];
    let crmComName = com[0]["CRM_COM_NAME"];

    let contact = rstAll[1];
    if (contact.length == 0) {
        $Tip("没有联系人");
        return;
    }
    let crmCusId = contact[0]["CRM_CUS_ID"];

    if (!contact[0]["ADM_ID"]) {
        let syncOk = await new Promise((resolve) => {
            let u = EWA.CP + "/business/sync_b2b/push_sup_main.jsp?sup_id=" + supDownId + "&op=PUSH";
            $J1(u, function(rst) {
                if (rst && rst.RST) {
                    return resolve(true);
                } else {
                    return resolve(false);
                }
            })
        });
        if (!syncOk) {
            $Tip("帐号开通失败，请联系管理员");
            return;
        }

        await new Promise((resolve) => {
            let ewa = EWA.F.FOS["@sys_frame_unid"];
            let u2 = ewa.getUrlClass();
            u2.RemoveEwa();
            u2.AddParameter("xmlname", "/business/crm/sales_crm.xml");
            u2.AddParameter("ITEMNAME", "CRM_CUS.F.login");
            u2.AddParameter("EWA_AJAX", "json_all");
            u2.AddParameter("CRM_CUS_ID", crmCusId);
            $J(u2.GetUrl(), function() {
                return resolve();
            });
        });

        //获取代理和联系人信息
        let rstAll2 = await new Promise((resolve) => {
            u1.AddParameter("SUP_DOWN_ID", supDownId);
            $J(u1.GetUrl(), function(rst) {
                return resolve(rst);
            });
        });
        contact = rstAll2[1];
        if (contact.length == 0) {
            $Tip("没有联系人");
            return;
        }
    }

    let admId = contact[0]["ADM_ID"];
    if (!admId) {
        $Tip("获取联系人登录帐号失败");
        return;
    }

    let crmCusName = contact[0]["CRM_CUS_NAME"];
    let u = EWA.CP + "/app-2017/crm/create-agent-login-qrcode.jsp?SUP_ID=" + supDownId + "&CRM_COM_ID=" + crmComId + "&ADM_ID=" + admId;
    $J(u, function(rst) {
        if (!rst.RST) {
            alert(rst.ERR);
            return;
        }
        let u = rst.URL;
        let img = EWA.CP + "/back_admin/common/qrcode.jsp?msg=" + u.toURL();
        let s = "<div style='text-align:center'><img width=260 src='" + img + "'>" +
            "<div style='margin:20px auto 0 auto;font-size:14px'>" + crmComName + "<br>" + crmCusName + "</div>" +
            "<div style='margin:20px auto 0 auto;font-size:16px'><a target='_blank' href='" + img +
            "' download='" + crmComName + "(" + crmCusName + ").jpg'>下载二维码</a></div></div>";
        window.top.$DialogHtml(s, '代理登录二维码', 300, 400);
    });
}

(function() {
    let ewa = EWA.F.FOS["@sys_frame_unid"];

    const templateButs=[
        {
            name:"短信模板",
            func:"openTemplate",
            para:"CLT_TYPE_SMS"
        },
        {
            name:"邮件模板",
            func:"extSendMail",
            para:""
        },
        {
            name:"短视频图片模板",
            func:"openTemplate",
            para:"CLT_TYPE_IMAGE"
        },
        {
            name:"海报模板",
            func:"openPosterTemplate",
            para:""
        }
        ];
    ewa.ext_openTemplates = function(e) {
        if(window._EWA_UI_DIALOG_COVERINDEX && _EWA_UI_DIALOG_COVERINDEX<300){
            _EWA_UI_DIALOG_COVERINDEX = 300; //覆盖查询多选框
        }
        const ss = ["<div id='add_menu_items_@sys_frame_unid'>"];
        for (let i = 0; i < templateButs.length; i++) {
            const item = templateButs[i];
            const s = `<div><a data-func="${item.func}" data-para="${item.para}">${item.name}</a></div>`;
            ss.push(s);
        }
        ss.push('</div>');
        const dia = $DialogHtml(ss.join(''), '推广模板', 222, null, false);
        const obj = $('#add_menu_items_@sys_frame_unid');
        obj.find('a').on('click', function() {
            ewa[$(this).attr("data-func")]($(this).attr("data-para"));
            dia.Close();
        });
        if(e && e.x && e.y){
            dia.Move(e.x, e.y+30)
        }
    };

    // 模板数据
    let templates=$J2MAP(JSON.parse("@EWA.FRAME.DATA.CRM_LEAD_TEMPLATE"),"CLT_TYPE");

    ewa.openTemplate=function(cltType){
        let u1=ewa.getUrlClass();
        u1.RemoveEwa();
        let itemname;

        itemname="CRM_LEAD_TEMPLATE.LF.V";
        u1.AddParameter("EWA_WIDTH","850px");
        u1.AddParameter("EWA_HEIGHT","450px");
        //u1.AddParameter("EWA_IN_DIALOG","1");
        u1.AddParameter("CLT_CAT","SUP_TYPE_CUS");
        u1.AddParameter("CLT_TYPE",cltType);
        let paras=u1.GetParas();
        EWA.UI.Dialog.OpenFrame("@sys_frame_unid","/business/crm/CRM_LEAD_TEMPLATE.xml",itemname,true,paras);

        // if(templates[cltType]){
        //     if(templates[cltType].CLT_NUM=="1"){
        //         itemname="CRM_LEAD_TEMPLATE.F.V";
        //         u1.AddParameter("CLT_ID",templates[cltType].CLT_ID);
        //     }else{
        //         itemname="CRM_LEAD_TEMPLATE.LF.V";
        //         u1.AddParameter("EWA_WIDTH=900px&EWA_HEIGHT=500px&CLT_TYPE="+cltType);
        //     }
        //     let paras=u1.GetParas();
        //     EWA.UI.Dialog.OpenFrame("@sys_frame_unid","/business/crm/CRM_LEAD_TEMPLATE.xml",itemname,false,paras);
        // }else{
        //     $Tip("制作中");
        // }
    }
    ewa.openPosterTemplate=function(){
        let u="@EWA.CP/poster-design/pd-list.jsp?PD_TAG=CRM_COM";
        window.top.AddTab(u);
    }
    ewa.extSendMail=function(){
        let trs=EWA.F.FOS["@sys_frame_unid"].SelectCheckedRows();
        if(trs.length==0){
            $Tip("请选择客户");
            return;
        }
        let tr= $(trs[0]);
        let email=trs[0].dataset.crmComEmail;
        let crmComId=tr.attr("ewa_key");
        let u1=ewa.getUrlClass();
        u1.RemoveEwa();
        //u1.AddParameter("XMLNAME","business/crm/mail_send.xml");
        //u1.AddParameter("ITEMNAME","MAIL_SEND.F.NM");
        u1.AddParameter("EWA_MTYPE","N");
        if(email){
            u1.AddParameter("TARGET_EMAIL",email);
        }
        u1.AddParameter("ms_ref","CRM_COM");
        u1.AddParameter("ms_ref_id",crmComId);
        u1.AddParameter("MS_LANG","zhcn");
        let paras=u1.GetParas();
        EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid","business/crm/mail_send.xml","MAIL_SEND.F.NM",false,paras);
    }

    ewa.valid_targets = ["CRM_COM_NAME","CONTACTS","CF_PROGRESS","SENT_NUM"
        , "QUERIES","CPS", "GRP_NUM","CLOSED_NUM","COS_NUM","CONTRACTS", "PROM_NUM"];
    //展开显示联系记录
    ewa.AddPreRow(function(frameUnid, tr, key, newTr, evt) {
        let target = evt.target;
        let cur_target_id = "";
        let target_obj;
        for (let i = 0; i < this.valid_targets.length; i++) {
            let id = this.valid_targets[i];
            if ($(target).hasClass("ewa-col-" + id)) { //点击td
                target_obj = target;
                cur_target_id = id;
            } else if (target.id == id) { //点击元素
                target_obj = $(target).parent()[0];
                cur_target_id = id;
            }
            if (cur_target_id) {
                break;
            }
        }
        if(!cur_target_id){
            cur_target_id="CRM_COM_NAME";
            target_obj=$(tr).find(".ewa-col-"+cur_target_id);
        }
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.AddParameter("EWA_AJAX", "INSTALL");
        u1.AddParameter("BY_CRM_COM_ID", key);
        u1.AddParameter("EWA_FRAME_UNID_PREFIX",key+"_");
        let sup_id = 0;
        sup_id = $(tr).attr("data-r-sup-id");
        if (cur_target_id == "CRM_COM_NAME") {
            u1.RemoveEwa();
            u1.AddParameter("crm_com_id", key);
            u1.AddParameter("EWA_FRAME_UNID_PREFIX",key+"_");
            if(sup_id && sup_id!="0"){
                u1.AddParameter("SUP_ID", sup_id);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
            }
            u1.SetRoot("@ewa.cp/business/sales/agent-index-2025.jsp?in_grp=1");
            u1.AddParameter("SUP_ID", sup_id);
        } else if (cur_target_id == "CONTACTS") {
            u1.AddParameter("CRM_COM_ID", key);
            u1.AddParameter("XMLNAME", "/business/crm/sales_crm.xml");
            u1.AddParameter("ITEMNAME", "CRM_RECORD.ListFrame.Modify");
        } else if (cur_target_id == "CF_PROGRESS") {
            u1.AddParameter("CRM_COM_ID", key);
            u1.AddParameter("CURRENT_YEAR", '@CURRENT_YEAR');
            u1.AddParameter("BY_CRM_COM_ID", 1);
            u1.AddParameter("XMLNAME", "/business/crm/crm_feedback.xml");
            u1.AddParameter("ITEMNAME", "CRM_FEEDBACK.LF.M");
        } else if (cur_target_id == "SENT_NUM") {
            u1.AddParameter("MS_REF","CRM_COM");
            u1.AddParameter("MS_REF_ID", key);
            u1.AddParameter("XMLNAME", "/business/crm/mail_send.xml");
            u1.AddParameter("ITEMNAME", "MAIL_SEND.LF.M");
        }  else {
            if(!sup_id || sup_id=="0"){
                $Tip("未签约客户");
                return;
            }

            if (cur_target_id == "QUERIES") { // 询价单
                u1.AddParameter("XMLNAME", "@xmlname");
                // u1.AddParameter("ITEMNAME", "index-sub-ENQ_MAIN.LF.M");
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("GRP_OR_ENQ","ENQ");
                u1.AddParameter("ITEMNAME", "index-GRP_MAIN.Lf.M");
            } else if (cur_target_id == "CPS") { // 预订单
                u1.AddParameter("XMLNAME", "/business/group/cp.xml");
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("ITEMNAME", "GRP_MAIN.LF.CP");
            } else if (cur_target_id == "GRP_NUM") { // 团列表
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("GRP_OR_ENQ","GRP");
                u1.AddParameter("XMLNAME", "@XMLNAME");
                u1.AddParameter("ITEMNAME", "index-GRP_MAIN.Lf.M");
            } else if (cur_target_id == "CLOSED_NUM") { // 团关闭
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("GRP_CLOSED","1");
                u1.AddParameter("XMLNAME", "@XMLNAME");
                u1.AddParameter("ITEMNAME", "index-GRP_MAIN.Lf.M");
            } else if (cur_target_id == "COS_NUM") { // 客人名单
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("FILTER","SALES");
                u1.AddParameter("XMLNAME", "/business/group/grp_customer.xml");
                u1.AddParameter("ITEMNAME", "GRP_COSTUMER.Lf.BookList");
            } else if (cur_target_id == "CONTRACTS") { // 客户协议
                u1.AddParameter("BY_SUP_ID", sup_id);
                u1.AddParameter("BY_FILE_TYPE", "PACT1");
                u1.AddParameter("XMLNAME", "@xmlname");
                u1.AddParameter("ITEMNAME", "index-CURRENCY_FILE.LF.V");
            } else if (cur_target_id == "PROM_NUM") { // 推广
                u1.AddParameter("CRM_COM_ID", key);
                u1.AddParameter("SUP_DOWN_ID", sup_id);
                u1.AddParameter("XMLNAME", "///business/agent/study-tour.xml");
                u1.AddParameter("ITEMNAME", "GRP_MAIN.LF.preEnroll");
            }
        }

        let cnt_td = newTr.cells[0];
        $(cnt_td).addClass('add-pre-row');

        $(target_obj).addClass("customer-add-row-cur-td");
        let ajax_url = u1.GetUrl();
        $Install(ajax_url, cnt_td.id, function() {
            // console.log('install ok');
        });
    });
    ewa.AddPreRowCheck = function(tr, key, evt) {
        return true;

        let target = evt.target;
        let objId;
        for (let i = 0; i < this.valid_targets.length; i++) {
            let id = this.valid_targets[i];
            if ($(target).hasClass("ewa-col-" + id) || target.id == id) {
                objId=id;
                break;
            }
        }
        if(objId){
            return true;
        }
    };
    ewa.AddPreRowCloseEvent = function(frameUnid, tr, key, newTr, evt) {
        $("#EWA_LF_@sys_frame_unid>tbody>tr>td.customer-add-row-cur-td").removeClass("customer-add-row-cur-td");
    };

    ewa.ReloadAfter = function() {
        //添加下一行事件元素添加样式
        for (let i = 0; i < this.valid_targets.length; i++) {
            $("#EWA_LF_" + this.Id + ">tbody>tr.ewa-lf-data-row>td.ewa-col-" + this.valid_targets[i])
                .addClass("customer-add-row-td");
        }
        //绑定按钮事件
        //打开客户面板
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butPanel]").on("click", function() {
            let name = $(this).attr("data-crm-com-name");
            let id = $(this).attr("data-crm-com-id");
            let u = "@EWA.CP/business/sales/agent-index.jsp?T=10&crm_com_id=" + id;
            if (top != window && top.AddTab) {
                top.AddTab(u, name);
            } else {
                window.open(u);
            }
        });
        //查看修改客户信息
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-col-CRM_COM_ID a").on("click", function() {
            let id = $(this).closest("tr").attr("ewa_key");
            let itemname="CRM_COM_NEW.Frame.Modify";
            let u1=ewa.getUrlClass();
            let paras="EWA_MTYPE=M&EWA_REDRAW=1&METHOD=DJ&CRM_COM_ID=" + id;
            if(u1.GetParameter("AUS_TYPE")){
                itemname="CRM_COM_NEW.Frame.New_easy";
                paras="EWA_MTYPE=M&CRM_COM_ID=" + id;
            }
            EWA.UI.Dialog.OpenReloadClose("@SYS_FRAME_UNID",
                "|business|crm|sales_crm.xml", itemname,
                false,
                paras);
        });
        //添加查看链接文字内容
        $("#EWA_LF_@SYS_FRAME_UNID .ewa-col-linkView a").html(ewa.Resources.lkView.GetInfo());

        //添加联系记录
        $("#EWA_LF_@SYS_FRAME_UNID input[id=butAddContact]").on("click", function() {
            let id = $(this).attr("data-crm-com-id");
            let p = 'EWA_MTYPE=N&CRM_COM_ID=' + id + "&COM_ID=" + id;
            EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID',
                '|business|crm|sales_crm.xml', 'CRM_RECORD.Frame.NewModify', false, p);
        });
        let u = new EWA_UrlClass(ewa.Url);
        if( "0" == u.GetParameter("CF_NEED")){ //全部客户
            $('#EWA_RESHOW_@SYS_FRAME_UNID .ewa-lf-menu').removeClass('ewa-lf-menu-marked');
            $('#EWA_RESHOW_@SYS_FRAME_UNID .ewa-lf-menu:eq(1)').addClass('ewa-lf-menu-marked')
        }


        $("#EWA_LF_@SYS_FRAME_UNID .ewa-lf-data-row .ewa-col-NEW_CUSTOMER span[title='New']").attr("title","请填写联系记录或客户反馈");

        // 行业子类title
        $("#EWA_LF_@SYS_FRAME_UNID>tbody>tr.ewa-lf-data-row>.ewa-col-CRM_COM_INDUSTRY_SUBCAT").each(function(){
            let span=$(this).find("#CRM_COM_INDUSTRY_SUBCAT");
            span.attr("title",span.text());
        })

        ewa.stickyColumns(4);
    }
    ewa.ReloadAfter();
})();

